import AppKit
import Foundation
import SwiftUI

/// Render-ready block. `id` is stable identity for diffing — caller assigns.
///
/// `@unchecked Sendable`: `Kind.image` carries `NSImage`, which is mutable
/// in principle. Caller contract: **do not mutate the `NSImage` after passing
/// it to a `Block`.** The layout pipeline extracts an immutable `CGImage`
/// snapshot at `make` time, so internal use is safe regardless.
struct Block: Identifiable, Equatable, @unchecked Sendable {
    let id: UUID
    let kind: Kind

    enum Kind: Equatable, @unchecked Sendable {
        /// `level` is the markdown heading level, 1...6. Out-of-range values
        /// clamp inside `BlockStyle.headingAttributed`.
        case heading(level: Int, inlines: [InlineNode])
        case paragraph(inlines: [InlineNode])
        case image(NSImage)
        /// Wraps the recursive `ListBlock` (a list item can contain a nested
        /// list) — the `Kind` enum stays flat by hiding the recursion in a
        /// dedicated struct.
        case list(ListBlock)
        case table(TableBlock)
        /// Fenced or indented code block. `language` is the info string
        /// from the opening fence (`nil` for indented blocks). `code` is
        /// the verbatim source — newlines preserved, no inline parsing.
        /// Rendered as a rounded container with a copy button in the top-
        /// right corner. Syntax highlighting is async — the cold render
        /// shows plain text; `Transcript2HighlightStorage` fills tokens
        /// in the background and triggers a single-row reload, after
        /// which `BlockStyle.codeBlockAttributed` produces a colored
        /// attributed string.
        case codeBlock(language: String?, code: String)
        /// CommonMark blockquote. Flat `[InlineNode]` payload — nested
        /// blocks inside a quote (lists, code blocks, nested quotes) are
        /// not modelled; the parser must collapse them to inlines or split
        /// them into separate sibling blocks. Rendered with a left bar
        /// and a rounded muted background.
        case blockquote(inlines: [InlineNode])
        /// `---` thematic break / horizontal rule. No payload — purely
        /// decorative spacer.
        case thematicBreak
        /// User-side message rendered as a right-aligned bubble. Long text
        /// auto-truncates with a tail "…" + a `>` chevron whose click
        /// surfaces the full message in a SwiftUI sheet (presentation
        /// concerns belong on the SwiftUI side; in-cell rendering stays
        /// stateless). Short messages render in full with no chevron.
        case userBubble(text: String)
    }
}

/// Tree-shaped list payload: top-level `ordered` flag + start index + items;
/// each item carries an optional checkbox marker and a sequence of paragraph
/// or nested-list contents. Recursion lives in `Content.list` (`indirect`),
/// matching CommonMark's list-inside-list nesting.
///
/// `startIndex` only matters for ordered lists. Defaults to 1 — the markdown
/// `1.` opener — and counts up monotonically; explicit non-1 starts (`5.`)
/// survive the round-trip.
struct ListBlock: Equatable, Sendable {
    let ordered: Bool
    let startIndex: Int
    let items: [Item]

    init(ordered: Bool, startIndex: Int = 1, items: [Item]) {
        self.ordered = ordered
        self.startIndex = startIndex
        self.items = items
    }

    struct Item: Equatable, Sendable {
        /// `nil` → use the list's bullet/ordered marker for this item;
        /// `false`/`true` → render an unchecked/checked checkbox instead
        /// (markdown task list syntax `- [ ]` / `- [x]`).
        let checkbox: Bool?
        let content: [Content]

        init(checkbox: Bool? = nil, content: [Content]) {
            self.checkbox = checkbox
            self.content = content
        }
    }

    /// `indirect` is on the enum, not the case — the recursion only occurs
    /// in `.list`, but Swift's heap-allocation rule for indirect enums is
    /// per-enum, and one indirect enum is enough.
    indirect enum Content: Equatable, Sendable {
        case paragraph([InlineNode])
        case list(ListBlock)
    }
}

/// GFM-style markdown table: 1 header row + N body rows + per-column
/// alignment. Cells are `[InlineNode]` so links / inline code / emphasis
/// inside cells survive to the renderer.
struct TableBlock: Equatable, Sendable {
    enum Alignment: Equatable, Sendable { case none, left, center, right }

    let header: [[InlineNode]]
    let rows: [[[InlineNode]]]
    let alignments: [Alignment]
}

/// Centralized typography + per-row geometry constants.
///
/// Per-kind attributed builders live here (`headingAttributed` /
/// `paragraphAttributed`). There is no `attributed(for: Block)` —
/// non-text kinds (image / table / tool) cannot be reduced to a single
/// `NSAttributedString`, so the layout pipeline switches on `Block.Kind`
/// directly and dispatches to the right primitive.
///
/// Inline emphasis (bold / italic / code / link) is supplied as `[InlineNode]`
/// trees produced by the upstream markdown parser; this layer walks the tree
/// and folds each node's styling into a single `NSAttributedString`. There is
/// no `String`-based overload — callers without a parser wrap raw text as
/// `[.text(s)]`. Keeping a single API removes the "what does `**bold**` do
/// here" ambiguity that two overloads would invite.
enum BlockStyle: Sendable {
    static let paragraphFont = NSFont.systemFont(ofSize: 14, weight: .regular)

    /// Horizontal padding inside the row.
    nonisolated static let blockHorizontalPadding: CGFloat = 16

    /// Per-kind vertical padding (top, bottom) inside each block's row.
    ///
    /// Designed so the **actual visible gap** between adjacent blocks reads
    /// consistent across kinds, rather than letting a single constant land
    /// at one value for soft-edged text and another for hard-edged tables /
    /// images.
    ///
    /// Body kinds (`paragraph`, `list`) carry symmetric 6/6 → 12pt p↔p gap.
    /// Hard-edged kinds (`table`, `image`) carry 8/8 → +2pt over body to
    /// compensate for the leading-illusion gap loss at borders. Headings
    /// are intentionally asymmetric: a wide top (scaled to font size) marks
    /// a section break, a near-zero bottom keeps the heading glued to the
    /// content it owns. The 6pt gap below a heading is contributed entirely
    /// by the following paragraph's `top`, so the rhythm stays uniform
    /// regardless of which heading level precedes the body text.
    nonisolated static func blockPadding(
        for kind: Block.Kind
    ) -> (top: CGFloat, bottom: CGFloat) {
        switch kind {
        case .heading(let level, _):
            let clamped = max(1, min(6, level))
            switch clamped {
            case 1: return (top: 24, bottom: 0)
            case 2: return (top: 16, bottom: 0)
            default: return (top: 10, bottom: 0)
            }
        case .paragraph, .list, .blockquote:
            // Blockquote sits in the soft-edged tier with paragraphs —
            // it has no container chrome, only a left bar, so it should
            // share paragraphs' rhythm rather than the harder 8/8 used
            // for visible-bordered blocks.
            return (top: 6, bottom: 6)
        case .image, .table, .codeBlock:
            return (top: 8, bottom: 8)
        case .userBubble:
            // Bubble already carries its own internal vertical padding;
            // the row pad here is the gap between the bubble and the
            // adjacent row's content. 8/8 matches `image`/`table`'s
            // hard-edged spacing tier.
            return (top: 8, bottom: 8)
        case .thematicBreak:
            // Thematic break is a thin line with no glyphs — it needs
            // wider top/bottom breathing room than text-edged kinds so
            // the rule doesn't visually attach to either neighbor.
            return (top: 12, bottom: 12)
        }
    }

    /// Cap for image height — wide-and-tall sources don't dominate the viewport.
    nonisolated static let imageMaxHeight: CGFloat = 360

    // MARK: - List geometry

    /// Vertical gap between adjacent list items at any nesting depth.
    /// Matches the old `MarkdownTheme.l3Item` value — the canonical "items
    /// breathe but don't fall apart" spacing for chat content.
    nonisolated static let listItemSpacing: CGFloat = 6

    /// Same gap, applied between paragraph blocks *inside* one list item
    /// (rare in practice but specified explicitly so multi-paragraph items
    /// don't cling to each other).
    nonisolated static let listIntraItemSpacing: CGFloat = 6

    /// Space between the marker column's right edge and the content's
    /// left edge. ½ em at body size — visually identical to
    /// `MarkdownTheme.MarkdownListMetrics.gap`.
    nonisolated static var listMarkerContentGap: CGFloat {
        paragraphFont.pointSize * 0.5
    }

    /// Checkbox edge length, slightly under cap-height of the body font.
    /// Bigger reads as a button; smaller fails to register as a control.
    nonisolated static var listCheckboxSize: CGFloat {
        paragraphFont.pointSize * 0.95
    }

    nonisolated static let listMarkerColor: NSColor = .secondaryLabelColor
    nonisolated static let listCheckboxCheckedColor: NSColor = .labelColor
    nonisolated static let listCheckboxUncheckedColor: NSColor = .secondaryLabelColor

    /// Bullet glyph "•" rendered at body font weight / size.
    nonisolated static func listBulletMarkerAttributed() -> NSAttributedString {
        NSAttributedString(string: "•", attributes: [
            .font: paragraphFont,
            .foregroundColor: listMarkerColor,
        ])
    }

    /// Ordered marker "N." rendered in monospaced body font so a column of
    /// "1." / "10." / "100." aligns at the dot.
    nonisolated static func listOrderedMarkerAttributed(_ n: Int) -> NSAttributedString {
        let font = NSFont.monospacedSystemFont(
            ofSize: paragraphFont.pointSize, weight: .regular)
        return NSAttributedString(string: "\(n).", attributes: [
            .font: font,
            .foregroundColor: listMarkerColor,
        ])
    }

    // MARK: - Table geometry

    nonisolated static let tableCellHorizontalPadding: CGFloat = 8
    nonisolated static let tableCellVerticalPadding: CGFloat = 10
    /// Floor on a column's `min` width. Empty columns / single-glyph columns
    /// would otherwise collapse to a sliver under the CSS-min-content
    /// derivation.
    nonisolated static let tableMinColumnWidth: CGFloat = 40
    /// Tables sit in the "structural" tier — see
    /// `structuralCornerRadius`. A 6pt corner reads as data/grid/IDE
    /// rather than as a soft personal-voice element, matching how
    /// Slack / Discord / Xcode treat their own data containers.
    nonisolated static var tableCornerRadius: CGFloat { structuralCornerRadius }

    nonisolated static let tableBorderColor: NSColor = .separatorColor

    /// Inner row separator. Same width as the outer border but a more muted
    /// color so the body grid reads as one block rather than a busy lattice.
    /// Resolves dynamically with appearance.
    nonisolated static let tableInnerDividerColor: NSColor = NSColor(name: nil) { appearance in
        let isDark = appearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        return isDark
            ? NSColor(white: 1, alpha: 0.10)
            : NSColor(white: 0, alpha: 0.06)
    }

    /// Header row tint — distinctly deeper than the zebra stripe so the
    /// header reads as a separate band rather than another body row.
    nonisolated static let tableHeaderBackground: NSColor = NSColor(name: nil) { appearance in
        let isDark = appearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        return isDark
            ? NSColor(white: 1, alpha: 0.14)
            : NSColor(white: 0, alpha: 0.08)
    }

    /// Subtle stripe applied to odd-indexed body rows. Eye-tracking aid
    /// across long horizontal rows; intentionally near-invisible at a
    /// glance.
    nonisolated static let tableZebraBackground: NSColor = NSColor(name: nil) { appearance in
        let isDark = appearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        return isDark
            ? NSColor(white: 1, alpha: 0.04)
            : NSColor(white: 0, alpha: 0.025)
    }

    /// Build a table cell's attributed string. `bold = true` for header
    /// cells. Reuses the inline IR walker so emphasis / code / link inside
    /// cells render the same as in paragraphs.
    nonisolated static func tableCellAttributed(
        inlines: [InlineNode], bold: Bool
    ) -> NSAttributedString {
        let baseFont: NSFont = bold
            ? NSFont.systemFont(ofSize: paragraphFont.pointSize, weight: .semibold)
            : paragraphFont
        let out = NSMutableAttributedString()
        appendInlines(inlines, into: out, base: baseAttributes(font: baseFont))
        return out
    }

    // MARK: - Corner-radius tiers

    /// "Soft" tier — speech / personal voice / emotional. Larger curve
    /// reads as friendly and rounded-organic. Visual-psychology
    /// research (Bar & Neta 2006 et al.): rounded shapes trigger a
    /// "safety / approachability" response distinct from sharp shapes'
    /// "precision / authority" response. Used for chat bubbles where
    /// the metaphor is a speech balloon.
    nonisolated static let softCornerRadius: CGFloat = 14

    /// "Structural" tier — data / code / grid / precision. Tight curve
    /// reads as engineering. Slack / Discord code blocks sit at 4pt;
    /// Notion at 6pt; Xcode panels at 0–4pt. Used for table outer
    /// border and code block container — anywhere the content wants
    /// to read as authoritative / technical rather than personal.
    nonisolated static let structuralCornerRadius: CGFloat = 6

    // MARK: - User bubble geometry

    /// Hard cap on bubble width — keeps long messages from spanning the
    /// full content column and re-establishes a right-side visual weight
    /// (bubble visibly hugs the right edge instead of looking like another
    /// paragraph).
    nonisolated static let userBubbleMaxWidth: CGFloat = 560

    /// Floor on the empty space to the bubble's left when the message is
    /// long enough to wrap — guarantees the bubble never bleeds into the
    /// content column's left edge.
    nonisolated static let bubbleMinLeftGutter: CGFloat = 60

    nonisolated static let bubbleHorizontalPadding: CGFloat = 16
    /// Matched to `bubbleCornerRadius` so the rounded corner's curve
    /// does not geometrically intrude into the text-baseline region —
    /// at `R > V`, top/bottom-line glyphs visually scrape the corner;
    /// at `R == V`, the curve sits flush with the text margin and the
    /// chevron's corner-anchored position lands on a uniform `R` offset
    /// from both the right and bottom edges. Aliased to
    /// `softCornerRadius` since the bubble's corner is the canonical
    /// "soft tier" anchor.
    nonisolated static var bubbleVerticalPadding: CGFloat { softCornerRadius }
    nonisolated static var bubbleCornerRadius: CGFloat { softCornerRadius }

    /// Bubble background — system accent at 15% so the tint shifts with
    /// the user's selected accent color and dark/light appearance.
    nonisolated static let bubbleFillColor: NSColor =
        NSColor.controlAccentColor.withAlphaComponent(0.15)

    /// Lines at and above this count *may* fold (subject to `userBubbleMinHiddenLines`).
    nonisolated static let userBubbleCollapseThreshold: Int = 12
    /// Hide fewer than this many lines reads worse than not folding at
    /// all (the chevron buys nothing). Effective fold lower bound is
    /// `threshold + minHiddenLines`.
    nonisolated static let userBubbleMinHiddenLines: Int = 3

    /// Chevron glyph drawing edge length.
    nonisolated static let chevronSize: CGFloat = 10
    /// Click target edge length — expanded around the glyph rect so a 10pt
    /// chevron is comfortable to hit.
    nonisolated static let chevronHitSize: CGFloat = 20

    /// User bubble plain text → attributed. No inline IR — user input is
    /// raw text, markdown emphasis is not parsed here (that's an assistant-
    /// content concern).
    nonisolated static func userBubbleAttributed(text: String) -> NSAttributedString {
        NSAttributedString(string: text, attributes: [
            .font: paragraphFont,
            .foregroundColor: NSColor.labelColor,
        ])
    }

    // MARK: - Code block geometry

    /// Code block uses the system monospaced font at the body font's
    /// point size — picking up SF Mono on system installs and falling
    /// back automatically. Same point size as paragraph text so a code
    /// block sandwiched between paragraphs reads as a sibling, not as
    /// a tonal shift.
    nonisolated static var codeBlockFont: NSFont {
        NSFont.monospacedSystemFont(ofSize: paragraphFont.pointSize, weight: .regular)
    }

    /// Background fill — Xcode "Default" canvas tone with a light-mode
    /// nudge for separation: `#F5F5F7` light / `#1F1F24` dark. Dark uses
    /// the editor's `DVTSourceTextBackground` verbatim (already darker
    /// than the chat window). Light shifts off pure `#FFFFFF` so the
    /// card edge is visible against an otherwise white transcript —
    /// `#F5F5F7` is the same off-white Apple's developer docs use for
    /// inline samples, so it still reads as "Xcode-adjacent."
    nonisolated static let codeBlockBackgroundColor: NSColor = NSColor(name: nil) { appearance in
        let isDark = appearance.bestMatch(from: [.darkAqua, .aqua]) == .darkAqua
        return isDark
            ? NSColor(srgbRed: 0x1F / 255.0, green: 0x1F / 255.0, blue: 0x24 / 255.0, alpha: 1)
            : NSColor(srgbRed: 0xF5 / 255.0, green: 0xF5 / 255.0, blue: 0xF7 / 255.0, alpha: 1)
    }

    /// Verbatim source → monospaced attributed string. Whitespace and
    /// newlines preserved; no inline parsing.
    ///
    /// Syntax highlighting is opt-in via `tokens`: when non-nil, walks
    /// the token list and emits per-segment foreground colors via
    /// `SyntaxTheme.color(for:scheme:)`. The colors are wrapped in a
    /// dynamic `NSColor(name:dynamicProvider:)` so a single attributed
    /// string tracks light/dark appearance without rebuild.
    ///
    /// Plain (`tokens == nil`) is the cold-render path used until
    /// `Transcript2HighlightStorage` finishes its async tokenize pass.
    nonisolated static func codeBlockAttributed(
        code: String, tokens: [SyntaxToken]?
    ) -> NSAttributedString {
        let font = codeBlockFont
        if let tokens, !tokens.isEmpty {
            let result = NSMutableAttributedString()
            for token in tokens {
                let scope = token.scope
                let color = NSColor(name: nil) { appearance in
                    let match = appearance.bestMatch(from: [.darkAqua, .aqua])
                    let scheme: ColorScheme = match == .darkAqua ? .dark : .light
                    return NSColor(SyntaxTheme.color(for: scope, scheme: scheme))
                }
                result.append(NSAttributedString(string: token.text, attributes: [
                    .font: font,
                    .foregroundColor: color,
                ]))
            }
            return result
        }
        return NSAttributedString(string: code, attributes: [
            .font: font,
            .foregroundColor: NSColor.labelColor,
        ])
    }

    /// Header band height — sized to a 11pt SF Symbol with a 4–5pt
    /// breathing margin top/bottom. Closer to Discord's compact
    /// 24pt strip than GitHub's chunkier 32–36pt header; chat content
    /// reads better with a low-profile chrome band.
    nonisolated static let codeBlockHeaderHeight: CGFloat = 24

    /// Reuses `tableHeaderBackground` so a code block's header band
    /// reads at the same tonal level as a table's header row —
    /// both are "this strip is chrome, content lives below it". The
    /// color is dynamic-resolving (alpha-on-white in light mode,
    /// alpha-on-black in dark mode), so it composites on top of
    /// `codeBlockBackgroundColor` and tracks appearance without any
    /// hand-tuned hex values.
    nonisolated static var codeBlockHeaderOverlayColor: NSColor { tableHeaderBackground }
    /// Body padding above and below the code text (inside the
    /// container, *below* the header band). Smaller than user
    /// bubble's 14pt — the header already eats the top visual weight,
    /// so 12 around the body keeps the block from reading too tall.
    nonisolated static let codeBlockBodyVerticalPadding: CGFloat = 12

    /// Header chrome label / glyph color. `secondaryLabel` so the band
    /// reads as chrome rather than competing with the body's syntax
    /// colors.
    nonisolated static let codeBlockHeaderForeground: NSColor = .secondaryLabelColor

    /// Header label / glyph point size. 11pt matches the SF Symbol
    /// weight calibration `codeBlockHeaderHeight` was chosen for.
    nonisolated static let codeBlockHeaderFontSize: CGFloat = 11

    /// Left inset for the language label inside the header. Aligned
    /// with `bubbleHorizontalPadding` so the label sits in the same
    /// vertical column as the body code beneath it — reads as a single
    /// flush left edge running the full block.
    nonisolated static var codeBlockHeaderLeftInset: CGFloat { bubbleHorizontalPadding }

    /// Right inset for the copy button hit zone. Anchored at the
    /// corner-radius pivot so the hit rect's right edge lands exactly
    /// where the rounded corner begins — the glyph itself (smaller than
    /// the hit zone) then floats just inside the curve, hugging the
    /// edge as the copy icon should as chrome.
    nonisolated static var codeBlockCopyRightInset: CGFloat { structuralCornerRadius }
    /// Hairline divider color between header and body.
    nonisolated static let codeBlockDividerColor: NSColor = .separatorColor

    // MARK: - Blockquote geometry

    /// Left accent bar. Tuned to the same values the prior renderer
    /// settled on — 4pt bar with a 12pt gap to the text, default
    /// secondary-label color so dark/light tracking is automatic.
    /// Quotes deliberately use **no background fill and no rounded
    /// container** — the bar alone does the "this is set apart"
    /// signaling, matching Slack / Discord / GitHub conventions where
    /// quotes are margin annotations, not standalone containers.
    nonisolated static let blockquoteBarColor: NSColor = .secondaryLabelColor
    nonisolated static let blockquoteBarWidth: CGFloat = 4
    nonisolated static let blockquoteBarGap: CGFloat = 12

    // MARK: - Thematic break geometry

    /// Hairline rule — 1pt at HiDPI, antialiased. Color uses the system
    /// separator so it tracks light/dark.
    nonisolated static let thematicBreakColor: NSColor = .separatorColor
    nonisolated static let thematicBreakHeight: CGFloat = 1

    /// Min/max width of the centered cell — the row spans the full table width
    /// (so the overlay scroller stays at the right edge), but the cell itself
    /// is clamped to this band by `CenteredRowView`. Width passed into
    /// `makeLayout` is also clamped, so the layout cache dedupes resizes
    /// inside the >max region.
    nonisolated static let minLayoutWidth: CGFloat = 460
    nonisolated static let maxLayoutWidth: CGFloat = 780

    nonisolated static func clampedLayoutWidth(forRowWidth rowWidth: CGFloat) -> CGFloat {
        min(maxLayoutWidth, max(minLayoutWidth, rowWidth))
    }

    /// Horizontal offset from the row's left edge to the centered cell.
    /// `CenteredRowView` and `Transcript2SelectionCoordinator` both go
    /// through this so the doc-coord ↔ layout-local conversion stays in
    /// sync with the visual layout.
    nonisolated static func cellOriginX(forRowWidth rowWidth: CGFloat) -> CGFloat {
        (rowWidth - clampedLayoutWidth(forRowWidth: rowWidth)) / 2
    }

    /// Marker attribute for inline code runs. `CTLineDraw` does not honor
    /// `.backgroundColor`, so we tag the run here and `TextLayout` extracts
    /// per-run rects from the typesetter output to paint the background
    /// itself with line-bounded geometry. Value is unused; presence is the
    /// signal.
    nonisolated static let inlineCodeAttributeKey =
        NSAttributedString.Key("CCTermInlineCode")

    /// Inline-code background. `secondarySystemFill` is the HIG-documented
    /// fill tier for "medium-sized layered shapes" — the next tier down,
    /// `tertiarySystemFill` (for "thin and small layered shapes"), reads as
    /// invisible against typical chat backgrounds; the next up,
    /// `systemFill`, is too heavy. `.secondarySystemFill` is already
    /// dark/light adaptive, so resolution happens automatically at draw
    /// time via `.cgColor`.
    nonisolated static let inlineCodeBackgroundColor: NSColor = .secondarySystemFill

    nonisolated static func paragraphAttributed(inlines: [InlineNode]) -> NSAttributedString {
        let out = NSMutableAttributedString()
        appendInlines(inlines, into: out, base: baseAttributes(font: paragraphFont))
        return out
    }

    nonisolated static func headingAttributed(level: Int,
                                              inlines: [InlineNode]) -> NSAttributedString {
        let out = NSMutableAttributedString()
        appendInlines(inlines, into: out, base: baseAttributes(font: headingFont(level: level)))
        return out
    }

    /// h1 26 / h2 22 / h3-h6 18. Markdown's six levels collapse to three
    /// visual tiers — chat content rarely needs deeper than h3, and shrinking
    /// h4-h6 below paragraph size makes them harder to scan than the
    /// preceding paragraph itself, defeating the point of a heading.
    nonisolated static func headingFont(level: Int) -> NSFont {
        let clamped = max(1, min(6, level))
        let size: CGFloat
        switch clamped {
        case 1: size = 26
        case 2: size = 22
        default: size = 18
        }
        return NSFont.systemFont(ofSize: size, weight: .semibold)
    }

    nonisolated private static func baseAttributes(font: NSFont)
        -> [NSAttributedString.Key: Any]
    {
        [
            .font: font,
            .foregroundColor: NSColor.labelColor,
        ]
    }

    /// Recursive walker. `base` carries the inherited attributes; each node
    /// derives a child attribute set, recurses, then drops back. Keeps the
    /// builder allocation-light — one `NSAttributedString.append` per leaf.
    nonisolated private static func appendInlines(_ nodes: [InlineNode],
                                                  into out: NSMutableAttributedString,
                                                  base: [NSAttributedString.Key: Any]) {
        for node in nodes {
            switch node {
            case .text(let s):
                out.append(NSAttributedString(string: s, attributes: base))

            case .strong(let children):
                appendInlines(children, into: out,
                              base: withTrait(base, adding: .bold))

            case .emphasis(let children):
                appendInlines(children, into: out,
                              base: withTrait(base, adding: .italic))

            case .strikethrough(let children):
                var attrs = base
                attrs[.strikethroughStyle] = NSUnderlineStyle.single.rawValue
                attrs[.strikethroughColor] = base[.foregroundColor] ?? NSColor.labelColor
                appendInlines(children, into: out, base: attrs)

            case .code(let s):
                var attrs = base
                attrs[.font] = inlineCodeFont(matching: base[.font] as? NSFont)
                // Marker only — actual fill happens in TextLayout.draw.
                attrs[inlineCodeAttributeKey] = true
                out.append(NSAttributedString(string: s, attributes: attrs))

            case .link(let children, let url):
                var attrs = base
                attrs[.link] = url
                attrs[.foregroundColor] = NSColor.linkColor
                attrs[.underlineStyle] = NSUnderlineStyle.single.rawValue
                appendInlines(children, into: out, base: attrs)

            case .lineBreak:
                // U+2028 line separator: line break inside a paragraph,
                // doesn't reset paragraph-style state. CTTypesetter honors it.
                out.append(NSAttributedString(string: "\u{2028}", attributes: base))
            }
        }
    }

    nonisolated private static func withTrait(_ attrs: [NSAttributedString.Key: Any],
                                              adding trait: NSFontDescriptor.SymbolicTraits)
        -> [NSAttributedString.Key: Any]
    {
        guard let font = attrs[.font] as? NSFont else { return attrs }
        let descriptor = font.fontDescriptor
            .withSymbolicTraits(font.fontDescriptor.symbolicTraits.union(trait))
        let next = NSFont(descriptor: descriptor, size: font.pointSize) ?? font
        var copy = attrs
        copy[.font] = next
        return copy
    }

    /// Inline code uses the system monospaced font at the surrounding text's
    /// point size (or paragraph size when the surrounding font is unknown).
    /// Weight follows the surrounding context so `**`code`**` stays bold.
    nonisolated private static func inlineCodeFont(matching surrounding: NSFont?) -> NSFont {
        let pointSize = surrounding?.pointSize ?? paragraphFont.pointSize
        let weight: NSFont.Weight = {
            guard let f = surrounding,
                  f.fontDescriptor.symbolicTraits.contains(.bold)
            else { return .regular }
            return .semibold
        }()
        return NSFont.monospacedSystemFont(ofSize: pointSize, weight: weight)
    }
}

import AppKit

/// `NSTableViewDataSource` + `NSTableViewDelegate` for the transcript table.
///
/// Single source of truth: `blocks: [Block]`. Layout is treated as a **pure
/// derivation** of `(block, width)` — `layoutCache` is a memo, not a parallel
/// truth. There is no `rows` mirror, no sync invariant between data and
/// layout, no diff anywhere.
///
/// ### Mutation paths
///
/// - **`apply(_:scroll:)`** — sync. Layouts compute lazily on `heightOfRow`
///   queries. Used for incremental updates (live messages, single removals,
///   tool-result updates).
/// - **`applyInBackground(_:scroll:)`** — layouts for the inserted blocks
///   compute on a detached `Task`, then a main hop installs them and runs
///   the structural change in one shot. Used by `Controller.loadInitial`'s
///   Phase 2 (large prepend after the viewport batch is already visible).
///
/// Both paths run their structural change inside `withScrollAdjustment`,
/// which interprets `ScrollState`:
/// - `.none` — no scroll work.
/// - `.top(id)` / `.bottom(id)` — direct scroll-to-position after the change.
/// - `.saveVisible(side)` — capture an anchor row's screen position before,
///   compensate scroll origin after so the row stays visually fixed across
///   the structural change. Same trick as Telegram's `saveScrollState` in
///   `TableView.layoutItems()`.
///
/// ### Width change (resize)
///
/// `layoutCache` is keyed by `(id, width)`. When the table width changes,
/// existing entries become misses and lazy-recompute. `tableFrameDidChange`
/// invalidates rows; live resize bounds work to visible rows;
/// `refillLayoutCache` (post-resize) reuses the same async pipeline
/// (`precomputeLayoutsInBackground` → `cacheLayouts` → `noteHeightOfRows`
/// under `.saveVisible(.visualTop)`).
///
/// ### Concurrency
///
/// Everything is `@MainActor`. Two distinct off-main lifecycles, kept
/// apart on purpose because their AppKit semantics differ:
///
/// - **`cacheRefillTask`** — `tableFrameDidChange` post-resize refill.
///   `numberOfRows` doesn't change; the only effect is to populate
///   `layoutCache` at the new width and `noteHeightOfRows` the rows whose
///   heights moved. Superseded only by the next `refillLayoutCache`. Loss is
///   CPU only — `heightOfRow` lazy-recomputes.
///
/// - **`applyInBackground`'s detached task** — row-mutation precompute.
///   Fire-and-forget, *not* tracked by a field, *not* cancellable: the
///   `insertRows` it carries is `dataSource`-changing critical work and
///   has to land. `Change.insert` resolves its anchor by id at apply-time,
///   so landing is robust against inflight `apply`s in between.
///
/// Cache anti-poison sits inside `cacheLayouts`: a write skips entries
/// already fresh at the same width, so an inflight task hopping in *after*
/// `apply .update`/`.remove` evicted and lazy-refilled an entry can't
/// overwrite the authoritative fresh layout with its older snapshot.
///
/// On top of that, a `mutationCounter` snapshot lets the refill task
/// drop its entire onMain block (including `noteHeightOfRows` and
/// `saveVisible`) when an `apply` ran during the task — running
/// `saveVisible` against stale AppKit heights (deferred re-query) would
/// otherwise jitter the anchor row.
@MainActor
final class Transcript2Coordinator: NSObject, NSTableViewDataSource, NSTableViewDelegate {
    weak var tableView: NSTableView? {
        didSet {
            // If `apply` was called before the table was attached, blocks
            // already exist; the freshly-attached table starts at
            // `numberOfRows = 0` until reloaded.
            if let table = tableView, oldValue !== tableView, !blocks.isEmpty {
                table.reloadData()
            }
        }
    }

    /// Notifies the controller after every successful mutation so SwiftUI
    /// observers on `blockCount` see the new value.
    var onBlockCountChanged: ((Int) -> Void)?

    /// Set by `Transcript2Controller` to forward chevron taps to the
    /// SwiftUI-owned sheet binding. The cell's mouseDown handler resolves
    /// the chevron hit, looks up the source `Block.Kind.userBubble(text:)`,
    /// and fires this — keeping the cross-layer signal narrow (one block
    /// id + the original text) so neither side reaches into the other's
    /// internals.
    var onUserBubbleSheetRequested: ((UUID, String) -> Void)?

    /// Cross-row text selection. Owns the selection dict; reads back into
    /// us through the helpers below (`block(atRow:)`, `textLayout(atRow:)`,
    /// `attributedString(forBlockId:)`, `markCellNeedsDisplay(blockId:)`).
    let selection: Transcript2SelectionCoordinator

    /// Async-filled per-block side data. Currently backs syntax tokens
    /// for code blocks; future highlight-shaped derivatives (diff hunks,
    /// inline annotations) will share the same storage by adding scopes.
    /// `apply` lifecycle wires `schedule` / `drop` calls; `onDidFill`
    /// drives a single-row reload after tokens land.
    let highlightStorage: Transcript2HighlightStorage

    init(syntaxEngine: SyntaxHighlightEngine? = nil) {
        self.selection = Transcript2SelectionCoordinator()
        self.highlightStorage = Transcript2HighlightStorage(engine: syntaxEngine)
        super.init()
        self.selection.transcript = self
        self.highlightStorage.onDidFill = { [weak self] id in
            self?.handleHighlightDidFill(blockId: id)
        }
    }

    /// Late-bind a syntax engine. Hosts that read `\.syntaxEngine` from
    /// SwiftUI environment hop here after `body` resolves the value.
    /// On `nil → engine` transition, every currently-installed block is
    /// re-scheduled so cold-loaded code blocks pick up tokens; passing
    /// the same engine again is harmless (the per-block generation guard
    /// dedupes redundant in-flight tasks).
    func attachSyntaxEngine(_ engine: SyntaxHighlightEngine?) {
        let wasAttached = highlightStorage.hasEngine
        highlightStorage.setEngine(engine)
        guard !wasAttached, engine != nil else { return }
        for block in blocks { highlightStorage.schedule(block) }
    }

    private var blocks: [Block] = []

    /// Memo of `(block, width) -> RowLayout`. Keyed by id so updates and
    /// removes can evict in O(1). The `width` field invalidates the entry
    /// when the table width changes — lookups at a different width treat the
    /// entry as a miss and overwrite it on recompute, so the cache never
    /// holds layouts at multiple widths simultaneously.
    private var layoutCache: [UUID: CachedLayout] = [:]

    private struct CachedLayout {
        let width: CGFloat
        let layout: RowLayout
    }

    /// Tracks the `tableFrameDidChange` post-resize layout refill task.
    /// Superseded only by the next `refillLayoutCache`. `applyInBackground`'s
    /// detached task is intentionally *not* stored here — it's
    /// fire-and-forget so an in-flight row-mutation can't be interrupted
    /// by an unrelated cancel path.
    private var cacheRefillTask: Task<Void, Never>?

    /// Bumped on every `apply`. The refill task captures it at start; if
    /// it drifts during the task run, the entire onMain block (cache
    /// writes, `noteHeightOfRows`, `saveVisible`) is dropped. Reason: the
    /// `saveVisible` anchor math relies on AppKit re-querying heights for
    /// rows we just `noteHeightOfRows`'d, but that re-query is deferred
    /// to the next layout pass — so running `applyAnchor` immediately
    /// after compensates against stale internal heights and the row
    /// visually jumps when AppKit eventually catches up. Skipping refill
    /// in this case is harmless: `apply`'s own scroll already settled the
    /// post-mutation state, and `heightOfRow` lazy-fills missing layouts
    /// on demand. `applyInBackground` doesn't bump because its own
    /// row-mutation is the change-event for its own scroll handling.
    private var mutationCounter: UInt64 = 0

    // MARK: - Read-only snapshot

    var blockIds: [UUID] { blocks.map(\.id) }

    /// Width that rows are laid out at — clamped to
    /// `BlockStyle.[min,max]LayoutWidth`. Driven by the single column's
    /// `.autoresizingMask` (which tracks the table width). Returns 0 if
    /// the table isn't attached or hasn't been sized yet.
    ///
    /// Clamping here is the single source of truth: `makeLayout` sees the
    /// clamped width, `layoutCache` keys on it, and `CenteredRowView` /
    /// `Transcript2SelectionCoordinator` both consume `BlockStyle`'s
    /// helpers to stay in sync. Window resizes that don't cross the
    /// clamp boundary land on the same cache entry — no relayout.
    var layoutWidth: CGFloat {
        guard let raw = tableView?.tableColumns.first?.width, raw > 0 else { return 0 }
        return BlockStyle.clampedLayoutWidth(forRowWidth: raw)
    }

    /// Last `layoutWidth` we processed in `tableFrameDidChange`. Used to
    /// short-circuit notifications whose underlying column-width change
    /// didn't move the clamped value (resize within the >max band).
    /// Sentinel `-1` will not match any real width on first run.
    private var lastLayoutWidth: CGFloat = -1

    /// Visible-region height of the enclosing scroll view. Returns 0 if
    /// no scroll view is attached.
    var viewportHeight: CGFloat {
        tableView?.enclosingScrollView?.contentView.bounds.height ?? 0
    }

    private var transcriptScrollView: Transcript2ScrollView? {
        tableView?.enclosingScrollView as? Transcript2ScrollView
    }

    /// Forwarders for `Transcript2ScrollView`'s scroller-hidden refcount.
    /// Silently no-op when no scroll view is attached — push/pop balance
    /// holds because both will no-op together.
    func pushScrollerHidden() { transcriptScrollView?.pushScrollerHidden() }
    func popScrollerHidden()  { transcriptScrollView?.popScrollerHidden() }

    // MARK: - Mutation: sync

    func apply(_ changes: [Transcript2Controller.Change],
               scroll: Transcript2Controller.ScrollState = .none) {
        // Bump so any inflight `cacheRefillTask` discards its onMain on
        // hop. We don't cancel here: the counter is the actual guard, and
        // `cacheRefillTask` polices its own lifetime via the next
        // `refillLayoutCache`. Discarding refill in this window matters
        // because its `saveVisible` would compensate against stale AppKit
        // heights (deferred re-query) — running on top of `apply`'s own
        // settled scroll would jitter the anchor row.
        mutationCounter &+= 1

        let table = tableView
        if let table {
            withScrollAdjustment(scroll, in: table) {
                table.beginUpdates()
                for change in changes {
                    applyStructuralChange(change, in: table)
                }
                table.endUpdates()
            }
        } else {
            // Table not attached. Just mutate `blocks`; future attach will
            // `reloadData()`. Scroll state is meaningless without a table.
            for change in changes {
                applyStructuralChange(change, in: nil)
            }
        }

        onBlockCountChanged?(blocks.count)
    }

    // MARK: - Mutation: off-main (Phase 2 of loadInitial, future use cases)

    /// Layouts for the inserted blocks compute on a detached task; a single
    /// main hop installs them and runs the structural changes under
    /// `scroll`.
    ///
    /// **Fire-and-forget.** The task is not tracked and not cancellable:
    /// row-mutation is `dataSource` critical-path work that must land.
    /// `Change.insert`'s id-based anchor resolves at apply-time, so
    /// landing stays correct across any `apply`s that ran in between.
    /// Layout entries enter the cache only on width match; a drifted
    /// width keeps the row-mutation but skips the cache write
    /// (`heightOfRow` lazy-recomputes at the new width).
    ///
    /// `completion` fires on main exactly once, in every outcome
    /// (succeeded, table-detached, zero-width). Callers use it to balance
    /// paired lifecycle work (e.g. scroller push/pop) that must survive
    /// the async hop.
    func applyInBackground(_ changes: [Transcript2Controller.Change],
                           scroll: Transcript2Controller.ScrollState,
                           completion: @MainActor @escaping () -> Void = {}) {
        guard tableView != nil else { completion(); return }
        let width = layoutWidth
        guard width > 0 else { completion(); return }

        // Only `.insert` carries new blocks; `.remove` / `.update` either
        // don't add layouts or evict them. `.update`'s replacement layout
        // is computed lazily by `applyStructuralChange` after the main hop.
        let toCompute: [Block] = changes.flatMap { change -> [Block] in
            if case .insert(_, let blocks) = change { return blocks }
            return []
        }

        // Snapshot highlight tokens on MainActor before detaching — the
        // off-main loop reads per-block tokens from this dict instead of
        // hopping back to the actor mid-iteration. New tokens that land
        // between this snapshot and the main hop are picked up by the
        // `onDidFill` reload path independently.
        let tokensSnapshot = highlightStorage.snapshot()

        Task.detached(priority: .userInitiated) { [weak self] in
            var entries: [(UUID, RowLayout)] = []
            entries.reserveCapacity(toCompute.count)
            for block in toCompute {
                entries.append((block.id, Self.makeLayout(
                    for: block, width: width, tokens: tokensSnapshot)))
            }
            await MainActor.run { [entries] in
                defer { completion() }
                guard let self, let table = self.tableView else { return }
                self.withScrollAdjustment(scroll, in: table) {
                    if self.layoutWidth == width {
                        self.cacheLayouts(entries, width: width)
                    }
                    table.beginUpdates()
                    for change in changes {
                        self.applyStructuralChange(change, in: table)
                    }
                    table.endUpdates()
                }
                self.onBlockCountChanged?(self.blocks.count)
            }
        }
    }

    // MARK: - Structural change (mechanical, no scroll, no scheduling)

    private func applyStructuralChange(_ change: Transcript2Controller.Change,
                                       in table: NSTableView?) {
        switch change {
        case .insert(let after, let new):
            guard !new.isEmpty else { return }
            let idx: Int
            if let after {
                guard let i = blocks.firstIndex(where: { $0.id == after }) else { return }
                idx = i + 1
            } else {
                idx = 0
            }
            blocks.insert(contentsOf: new, at: idx)
            for block in new { highlightStorage.schedule(block) }
            table?.insertRows(at: IndexSet(idx ..< idx + new.count),
                              withAnimation: [.effectFade])

        case .remove(let ids):
            let idSet = Set(ids)
            var indexes = IndexSet()
            for (i, b) in blocks.enumerated() where idSet.contains(b.id) {
                indexes.insert(i)
            }
            guard !indexes.isEmpty else { return }
            for i in indexes.reversed() { blocks.remove(at: i) }
            for id in idSet {
                removeCachedLayout(for: id)
                selection.dropEntry(blockId: id)
                highlightStorage.drop(blockId: id)
            }
            table?.removeRows(at: indexes, withAnimation: [.effectFade])

        case .update(let id, let kind):
            guard let i = blocks.firstIndex(where: { $0.id == id }) else { return }
            let updated = Block(id: id, kind: kind)
            blocks[i] = updated
            removeCachedLayout(for: id)
            // Drop stale highlight tokens (the new kind may carry a
            // different code or language, or no highlight at all). The
            // generation guard inside `drop` also invalidates any
            // in-flight task for the previous content, then `schedule`
            // kicks the new pass for the replacement kind.
            highlightStorage.drop(blockId: id)
            highlightStorage.schedule(updated)
            // Content replacement invalidates the prior selection range
            // (offsets no longer index into the same string). Drop now so
            // the upcoming `reloadData(forRowIndexes:)` runs viewFor with
            // a clean empty selection on the recycled cell.
            selection.dropEntry(blockId: id)
            let idx = IndexSet(integer: i)
            table?.reloadData(forRowIndexes: idx,
                              columnIndexes: IndexSet(integer: 0))
            table?.noteHeightOfRows(withIndexesChanged: idx)
        }
    }

    // MARK: - Highlight tokens fill-in

    /// Called by `highlightStorage` after async tokens land for `blockId`.
    /// Evicts the stale (plain) `RowLayout` and reloads the single row.
    /// Skips `noteHeightOfRows` because token fill changes only color,
    /// not glyph metrics — a re-layout pass would be a wasted query.
    private func handleHighlightDidFill(blockId: UUID) {
        guard let table = tableView,
              let row = blocks.firstIndex(where: { $0.id == blockId })
        else { return }
        removeCachedLayout(for: blockId)
        table.reloadData(forRowIndexes: IndexSet(integer: row),
                         columnIndexes: IndexSet(integer: 0))
    }

    // MARK: - Scroll adjustment

    /// Wraps a structural-change closure with the requested scroll behavior.
    /// `.saveVisible` disables implicit animations so the height/insert
    /// transition doesn't race with the scroll-origin compensation.
    private func withScrollAdjustment(_ scroll: Transcript2Controller.ScrollState,
                                      in tableView: NSTableView,
                                      body: () -> Void) {
        switch scroll {
        case .none:
            body()
        case .top(let id):
            body()
            scrollRowToTop(id: id, in: tableView)
        case .bottom(let id):
            body()
            scrollRowToBottom(id: id, in: tableView)
        case .saveVisible(let side):
            let anchor = captureAnchor(side: side, in: tableView)
            // Disable both NSAnimationContext (row-height transition) and
            // CATransaction (layer-backed ClipView's bounds.origin animation
            // from `scroll(to:)`) so they don't race.
            NSAnimationContext.beginGrouping()
            NSAnimationContext.current.duration = 0
            NSAnimationContext.current.allowsImplicitAnimation = false
            CATransaction.begin()
            CATransaction.setDisableActions(true)
            body()
            if let anchor { applyAnchor(anchor, in: tableView) }
            CATransaction.commit()
            NSAnimationContext.endGrouping()
        }
    }

    private struct ScrollAnchor {
        let blockId: UUID
        /// `rect.origin.y` for `.visualTop`, `rect.maxY` for `.visualBottom`.
        let oldRefY: CGFloat
        let oldScrollY: CGFloat
        let side: Transcript2Controller.ScrollState.Side
    }

    private func captureAnchor(side: Transcript2Controller.ScrollState.Side,
                               in tableView: NSTableView) -> ScrollAnchor? {
        guard let scrollView = tableView.enclosingScrollView else { return nil }
        let visible = tableView.rows(in: tableView.visibleRect)
        guard visible.location != NSNotFound, visible.length > 0 else { return nil }

        // NSTableView is flipped (default): smallest visible row index = top
        // of viewport; largest = bottom.
        let anchorRow: Int
        switch side {
        case .visualTop:
            anchorRow = visible.location
        case .visualBottom:
            anchorRow = visible.location + visible.length - 1
        }
        guard blocks.indices.contains(anchorRow) else { return nil }
        let rect = tableView.rect(ofRow: anchorRow)
        let refY: CGFloat = (side == .visualTop) ? rect.origin.y : rect.maxY
        return ScrollAnchor(
            blockId: blocks[anchorRow].id,
            oldRefY: refY,
            oldScrollY: scrollView.contentView.bounds.origin.y,
            side: side)
    }

    private func applyAnchor(_ anchor: ScrollAnchor, in tableView: NSTableView) {
        guard let scrollView = tableView.enclosingScrollView else { return }
        guard let newRow = blocks.firstIndex(where: { $0.id == anchor.blockId }) else {
            return
        }
        let newRect = tableView.rect(ofRow: newRow)
        let newRefY: CGFloat = (anchor.side == .visualTop) ? newRect.origin.y : newRect.maxY
        let delta = newRefY - anchor.oldRefY
        if abs(delta) > 0.5 {
            scrollView.contentView.scroll(
                to: NSPoint(x: scrollView.contentView.bounds.origin.x,
                            y: anchor.oldScrollY + delta))
        }
    }

    private func scrollRowToTop(id: UUID, in tableView: NSTableView) {
        guard let row = blocks.firstIndex(where: { $0.id == id }),
              let scrollView = tableView.enclosingScrollView else { return }
        let target = tableView.rect(ofRow: row).origin.y
        scrollView.contentView.scroll(
            to: NSPoint(x: scrollView.contentView.bounds.origin.x, y: target))
    }

    private func scrollRowToBottom(id: UUID, in tableView: NSTableView) {
        guard let row = blocks.firstIndex(where: { $0.id == id }),
              let scrollView = tableView.enclosingScrollView else { return }
        let rect = tableView.rect(ofRow: row)
        let viewportH = scrollView.contentView.bounds.height
        let target = max(0, rect.maxY - viewportH)
        scrollView.contentView.scroll(
            to: NSPoint(x: scrollView.contentView.bounds.origin.x, y: target))
    }

    // MARK: - Layout cache

    /// All access to `layoutCache` goes through these helpers and the lazy
    /// `layout(for:width:)` path below. Direct subscripting from elsewhere
    /// is banned by convention so the width invariant and the "evict on
    /// input change" discipline have a single audit point.

    /// Writes precomputed layouts into the cache. Skips an entry if a
    /// fresh layout at the same width is already present —— that means the
    /// sync `apply` path has run `removeCachedLayout` + a layout pass
    /// since this batch was computed, and the lazy re-fill it triggered
    /// is the authoritative entry. Overwriting it with our (older
    /// snapshot's) layout would poison the cache.
    private func cacheLayouts(_ entries: [(UUID, RowLayout)], width: CGFloat) {
        for (id, layout) in entries {
            if layoutCache[id]?.width == width { continue }
            layoutCache[id] = CachedLayout(width: width, layout: layout)
        }
    }

    private func removeCachedLayout(for id: UUID) {
        layoutCache.removeValue(forKey: id)
    }

    private func indexesNeedingLayoutRefresh(at width: CGFloat) -> [Int] {
        blocks.indices.filter { layoutCache[blocks[$0].id]?.width != width }
    }

    // MARK: - Lazy layout (heightOfRow / viewFor)

    private func layout(for block: Block, width: CGFloat) -> RowLayout {
        if let c = layoutCache[block.id], c.width == width {
            return c.layout
        }
        let layout = Self.makeLayout(
            for: block, width: width,
            tokens: highlightStorage.snapshot())
        layoutCache[block.id] = CachedLayout(width: width, layout: layout)
        return layout
    }

    /// Pure: `(block, width, tokens) -> RowLayout`. `nonisolated static`
    /// so the background prefetch task can call it off-MainActor.
    /// `tokens` is a snapshot of `Transcript2HighlightStorage` taken on
    /// MainActor before the detached task starts; passing the snapshot in
    /// keeps the per-block lookup actor-free during the off-main loop.
    /// Defaults to empty so call sites that genuinely don't want
    /// highlight (e.g. `Transcript2Controller.sliceForViewport`'s
    /// height-only probe) can omit the parameter.
    nonisolated static func makeLayout(
        for block: Block, width: CGFloat,
        tokens: [Transcript2HighlightKey: [SyntaxToken]] = [:]
    ) -> RowLayout {
        let contentWidth = max(0, width - 2 * BlockStyle.blockHorizontalPadding)
        switch block.kind {
        case .heading(let level, let inlines):
            return .text(TextLayout.make(
                attributed: BlockStyle.headingAttributed(level: level, inlines: inlines),
                maxWidth: contentWidth))
        case .paragraph(let inlines):
            return .text(TextLayout.make(
                attributed: BlockStyle.paragraphAttributed(inlines: inlines),
                maxWidth: contentWidth))
        case .image(let image):
            return .image(ImageLayout.make(
                image: image,
                maxWidth: contentWidth,
                maxHeight: BlockStyle.imageMaxHeight))
        case .list(let listBlock):
            return .list(ListLayout.make(block: listBlock, maxWidth: contentWidth))
        case .table(let tableBlock):
            return .table(TableLayout.make(block: tableBlock, maxWidth: contentWidth))
        case .codeBlock(let language, let code):
            let codeTokens = tokens[
                Transcript2HighlightKey(blockId: block.id, scope: .codeBlock)]
            return .codeBlock(CodeBlockLayout.make(
                code: code, language: language,
                tokens: codeTokens, maxWidth: contentWidth))
        case .blockquote(let inlines):
            return .blockquote(BlockquoteLayout.make(inlines: inlines, maxWidth: contentWidth))
        case .thematicBreak:
            return .thematicBreak(ThematicBreakLayout.make(maxWidth: contentWidth))
        case .userBubble(let text):
            return .userBubble(UserBubbleLayout.make(text: text, maxWidth: contentWidth))
        }
    }

    // MARK: - User bubble sheet

    /// Forwards a chevron click on the user bubble at `id` to the SwiftUI
    /// sheet binding (via `onUserBubbleSheetRequested`). No `.update` path
    /// — fold state is absent from the layout; the sheet is the place to
    /// read the full message. No-op if `id` is unknown or doesn't point
    /// at a `userBubble`.
    func requestUserBubbleSheet(id: UUID) {
        guard let i = blocks.firstIndex(where: { $0.id == id }),
              case .userBubble(let text) = blocks[i].kind
        else { return }
        onUserBubbleSheetRequested?(id, text)
    }

    // MARK: - Width-change driven invalidation

    @objc func tableFrameDidChange(_ note: Notification) {
        guard let tableView, !blocks.isEmpty else { return }
        // Resizes inside the >max clamp band leave `layoutWidth` unchanged.
        // `CenteredRowView.layout()` still re-runs (driven by NSTableView's
        // tile pass) and repositions the cell horizontally, but no row needs
        // its layout invalidated — so skip the reload/noteHeightOfRows pair.
        let width = layoutWidth
        if width == lastLayoutWidth { return }
        lastLayoutWidth = width
        if tableView.inLiveResize {
            // Bounded per-frame layout work: only invalidate visible rows.
            // Off-screen rows keep their stale heights and stale cached
            // layouts — invisible to the user and repaired by the
            // post-resize background prefetch.
            let visible = tableView.rows(in: tableView.visibleRect)
            guard visible.location != NSNotFound, visible.length > 0 else { return }
            invalidate(rows: IndexSet(visible.location ..< visible.location + visible.length),
                       in: tableView)
        } else {
            // Outside live resize, frame changes are programmatic / one-off
            // (initial layout, window animation). Invalidate everything;
            // AppKit re-queries lazily on next layout pass.
            invalidate(rows: IndexSet(0 ..< blocks.count), in: tableView)
        }
    }

    /// `reloadData(forRowIndexes:)` re-runs `viewFor` so the cell picks up
    /// the layout at the current width; `noteHeightOfRows` tells AppKit to
    /// re-query `heightOfRow` so cell frames resize. Both are needed —
    /// dropping `reloadData(forRowIndexes:)` leaves visible cells holding
    /// the old `RowLayout` (drawn at old width) inside a newly-resized
    /// frame, so glyphs land at the wrong x positions during a live resize.
    ///
    /// The no-animation grouping is the live-resize fix: by default
    /// `noteHeightOfRows` repositions rows below via an implicit
    /// NSAnimationContext / CATransaction animation, while cell-internal
    /// redraw is synchronous (`needsDisplay = true` in `layout` setter).
    /// During fast resize the cell already paints at the new height while
    /// the row below is still mid-animation at its old y — visually the
    /// rows overlap. Zeroing duration and disabling layer actions makes
    /// row repositioning land in the same display cycle as the redraw.
    /// Mirrors Telegram's `TableView.layoutIfNeeded(with:oldWidth:)` →
    /// `noteHeightOfRow(_:false)` path, which does the same suppression.
    private func invalidate(rows indexes: IndexSet, in tableView: NSTableView) {
        guard !indexes.isEmpty else { return }
        NSAnimationContext.beginGrouping()
        NSAnimationContext.current.duration = 0
        NSAnimationContext.current.allowsImplicitAnimation = false
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        tableView.beginUpdates()
        tableView.reloadData(forRowIndexes: indexes,
                             columnIndexes: IndexSet(integer: 0))
        tableView.noteHeightOfRows(withIndexesChanged: indexes)
        tableView.endUpdates()
        CATransaction.commit()
        NSAnimationContext.endGrouping()
    }

    // MARK: - Background prefetch (post-live-resize)

    func refillLayoutCache() {
        guard let tableView else { return }
        let width = layoutWidth
        guard width > 0 else { return }
        let staleIdxs = indexesNeedingLayoutRefresh(at: width)
        // Empty → fully cached at this width. Common case when resize
        // ended at the start width with no actual change. No push
        // happened, so no pop needed.
        guard !staleIdxs.isEmpty else { return }

        let snapshot = staleIdxs.map { blocks[$0] }
        let snapshotCounter = mutationCounter
        let tokensSnapshot = highlightStorage.snapshot()
        // Push covers the async layout window so the scroller stays hidden
        // through the post-resize relayout. Popped via the task's defer in
        // every outcome (cancelled, drifted, succeeded).
        pushScrollerHidden()

        cacheRefillTask?.cancel()
        cacheRefillTask = Task.detached(priority: .userInitiated) { [weak self] in
            var entries: [(UUID, RowLayout)] = []
            entries.reserveCapacity(snapshot.count)
            var aborted = false
            for block in snapshot {
                if Task.isCancelled { aborted = true; break }
                entries.append((block.id, Self.makeLayout(
                    for: block, width: width, tokens: tokensSnapshot)))
            }
            await MainActor.run { [entries] in
                defer { self?.popScrollerHidden() }
                if aborted { return }
                guard let self, let table = self.tableView,
                      self.layoutWidth == width else { return }
                // mutationCounter drift → an `apply` ran during the task.
                // Skip the entire onMain (cache writes, noteHeightOfRows,
                // saveVisible). Reason: noteHeightOfRows is deferred to
                // the next layout pass, so `applyAnchor` would run
                // against AppKit's still-stale internal heights and
                // produce a wrong scroll compensation; the row visually
                // jumps when AppKit eventually re-queries. `apply` has
                // already settled its own scroll, and `heightOfRow` will
                // lazy-fill the layouts as needed.
                guard self.mutationCounter == snapshotCounter else { return }
                // applyInBackground (fire-and-forget, counter-untracked)
                // may have shifted indices. Re-resolve via id so
                // noteHeightOfRows targets the current dataSource state.
                let idxs = entries.compactMap { (id, _) -> Int? in
                    self.blocks.firstIndex { $0.id == id }
                }
                self.withScrollAdjustment(.saveVisible(.visualTop), in: table) {
                    self.cacheLayouts(entries, width: width)
                    if !idxs.isEmpty {
                        table.noteHeightOfRows(withIndexesChanged: IndexSet(idxs))
                    }
                }
            }
        }
    }

    // MARK: - NSTableViewDataSource / Delegate

    func numberOfRows(in tableView: NSTableView) -> Int { blocks.count }

    func tableView(_ tableView: NSTableView, heightOfRow row: Int) -> CGFloat {
        guard blocks.indices.contains(row) else { return 1 }
        let width = layoutWidth
        let pad = BlockStyle.blockPadding(for: blocks[row].kind)
        return layout(for: blocks[row], width: width).totalHeight
            + pad.top + pad.bottom
    }

    func tableView(_ tableView: NSTableView,
                   rowViewForRow row: Int) -> NSTableRowView? {
        let id = NSUserInterfaceItemIdentifier("BlockRow")
        if let reused = tableView.makeView(withIdentifier: id, owner: self)
            as? CenteredRowView
        {
            return reused
        }
        let view = CenteredRowView()
        view.identifier = id
        return view
    }

    func tableView(_ tableView: NSTableView,
                   viewFor tableColumn: NSTableColumn?,
                   row: Int) -> NSView? {
        guard blocks.indices.contains(row) else { return nil }
        let width = layoutWidth
        let block = blocks[row]
        let cellLayout = layout(for: block, width: width)

        let id = NSUserInterfaceItemIdentifier("BlockCell")
        let cell: BlockCellView
        if let reused = tableView.makeView(withIdentifier: id, owner: self) as? BlockCellView {
            cell = reused
        } else {
            cell = BlockCellView()
            cell.identifier = id
        }
        cell.layout = cellLayout
        cell.padTop = BlockStyle.blockPadding(for: block.kind).top
        // Selection is keyed by block id, not by cell instance, so a
        // recycled cell scrolling onto a row that already had a selection
        // picks up the existing entry here. nil = no highlight.
        cell.blockId = block.id
        cell.selection = selection.selection(for: block.id)
        // Copy-feedback flash is per-cell transient state — clear it
        // on every reuse so a recycled cell doesn't carry a stale
        // checkmark onto a different code block.
        cell.resetCopiedFeedback()
        // Reinjected on every viewFor (cells are reused across rows) so
        // chevron mouseDown can hit `requestUserBubbleSheet` without
        // scanning the superview chain.
        cell.coordinator = self
        return cell
    }

    // MARK: - Selection helpers (consumed by SelectionCoordinator)

    /// Block at `row`, or `nil` if out of bounds. Selection-side reads
    /// must accept "no block here" because `applyInBackground`'s
    /// fire-and-forget hop can shrink `blocks` between the caller's
    /// row resolution and this read.
    func block(atRow row: Int) -> Block? {
        blocks.indices.contains(row) ? blocks[row] : nil
    }

    /// Block by id. Linear scan — selection paths touch ≤ N blocks, the
    /// dict-keyed lookup elsewhere is `layoutCache`'s job, not this one.
    func block(forId id: UUID) -> Block? {
        blocks.first { $0.id == id }
    }

    /// Selection-facing API for the block at `row`, or `nil` if the row
    /// is non-selectable (image, list). Goes through the lazy
    /// `layout(for:width:)` path so a row whose layout was evicted (or
    /// not yet computed) lazy-fills its cache entry as a side effect.
    func selectionAdapter(atRow row: Int) -> SelectionAdapter? {
        guard let block = block(atRow: row) else { return nil }
        return layout(for: block, width: layoutWidth).selectionAdapter
    }

    /// Selection-facing API keyed by block id (used by Cmd+A, copy, and
    /// other paths that don't have a row index handy).
    func selectionAdapter(forBlockId id: UUID) -> SelectionAdapter? {
        guard let block = block(forId: id) else { return nil }
        return layout(for: block, width: layoutWidth).selectionAdapter
    }

    /// Push the current selection state for `blockId` to its visible
    /// cell, which triggers `needsDisplay` via the cell's `didSet` if
    /// the value actually changed. No-op if the cell isn't currently
    /// visible — when it scrolls in, `viewFor` will read the live state
    /// from the selection dict.
    func markCellNeedsDisplay(blockId: UUID) {
        guard let table = tableView,
              let row = blocks.firstIndex(where: { $0.id == blockId })
        else { return }
        guard let cell = table.view(atColumn: 0, row: row, makeIfNecessary: false)
            as? BlockCellView
        else { return }
        cell.selection = selection.selection(for: blockId)
    }

}

import AppKit

/// One interactive hot zone in layout-local coords. Drives both cursor
/// swap (`resetCursorRects` registers `.pointingHand` over `rect`) and
/// click dispatch (`mouseDown` matches the point against `rect` and
/// runs `action`). Cell offsets `rect` by its draw origin before either
/// use; layouts emit hits in their own coordinate space.
struct InteractiveHit: Sendable {
    let rect: CGRect
    let action: HitAction
}

/// What clicking an `InteractiveHit` does. Three cases for three
/// independent behaviors — kept as a closed enum so the cell's
/// dispatch stays an exhaustive switch. Adding a fourth interaction
/// (e.g., "expand inline") = add a case here and a switch arm in
/// `BlockCellView.mouseDown`.
enum HitAction: Sendable {
    /// `.link`-attributed run. Cell opens via `NSWorkspace.shared.open`.
    case openURL(URL)
    /// User-bubble chevron. Cell forwards to
    /// `Transcript2Coordinator.requestUserBubbleSheet(id:)` (the
    /// block id lives on the cell, not the layout).
    case openUserBubbleSheet
    /// Code-block copy button. Cell writes the payload to the
    /// general pasteboard and triggers its transient checkmark
    /// feedback.
    case copyText(String)
}

/// Type-erased dispatch over the per-kind layout primitives. Holds whichever
/// `XxxLayout` value the block kind required, and exposes the things
/// downstream code asks for:
///
/// - `totalHeight` (consumed by `NSTableView.heightOfRow`)
/// - `measuredWidth` (used by the layout cache to detect width changes)
/// - `draw(in:origin:)` (invoked by the cell's `draw(_:)`)
/// - `selectionAdapter` / `iBeamRect` / `interactiveHits` (consumed
///   by the cell for selection + cursor rects + click dispatch)
///
/// Add a new layout primitive: add the case here, extend each method.
/// The cell view is enum-agnostic — it doesn't switch on cases, only
/// calls these uniform APIs.
enum RowLayout: @unchecked Sendable {
    case text(TextLayout)
    case image(ImageLayout)
    case list(ListLayout)
    case table(TableLayout)
    case codeBlock(CodeBlockLayout)
    case blockquote(BlockquoteLayout)
    case thematicBreak(ThematicBreakLayout)
    case userBubble(UserBubbleLayout)

    var totalHeight: CGFloat {
        switch self {
        case .text(let l): return l.totalHeight
        case .image(let l): return l.totalHeight
        case .list(let l): return l.totalHeight
        case .table(let l): return l.totalHeight
        case .codeBlock(let l): return l.totalHeight
        case .blockquote(let l): return l.totalHeight
        case .thematicBreak(let l): return l.totalHeight
        case .userBubble(let l): return l.totalHeight
        }
    }

    var measuredWidth: CGFloat {
        switch self {
        case .text(let l): return l.measuredWidth
        case .image(let l): return l.measuredWidth
        case .list(let l): return l.measuredWidth
        case .table(let l): return l.measuredWidth
        case .codeBlock(let l): return l.measuredWidth
        case .blockquote(let l): return l.measuredWidth
        case .thematicBreak(let l): return l.measuredWidth
        case .userBubble(let l): return l.measuredWidth
        }
    }

    /// Opaque chrome that must paint *before* the cell's selection band
    /// so the highlight composites on top, under the glyphs. Default is
    /// a no-op — only codeblock currently has an opaque card background
    /// that would otherwise hide the selection rect drawn by the cell.
    func drawBackplate(in ctx: CGContext, origin: CGPoint) {
        switch self {
        case .codeBlock(let l): l.drawBackplate(in: ctx, origin: origin)
        default: break
        }
    }

    func draw(in ctx: CGContext, origin: CGPoint) {
        switch self {
        case .text(let l): l.draw(in: ctx, origin: origin)
        case .image(let l): l.draw(in: ctx, origin: origin)
        case .list(let l): l.draw(in: ctx, origin: origin)
        case .table(let l): l.draw(in: ctx, origin: origin)
        case .codeBlock(let l): l.draw(in: ctx, origin: origin)
        case .blockquote(let l): l.draw(in: ctx, origin: origin)
        case .thematicBreak(let l): l.draw(in: ctx, origin: origin)
        case .userBubble(let l): l.draw(in: ctx, origin: origin)
        }
    }

    /// Region that should show the I-beam cursor on hover, in
    /// layout-local coords. `nil` means "the whole cell `bounds`" —
    /// matches `NSTextView`'s behavior of I-beam over the full frame
    /// for ordinary text blocks. Right-aligned / non-full-width
    /// layouts (currently: user bubble) override to confine the
    /// I-beam to their actual content rect, so empty gutter space
    /// outside the bubble keeps the default arrow.
    var iBeamRect: CGRect? {
        switch self {
        case .userBubble(let l): return l.bubbleRect
        default: return nil
        }
    }

    /// Interactive hot zones in layout-local coords — links + cell-
    /// internal controls (user bubble chevron, code-block copy
    /// button), unified as `(rect, action)`. The cell iterates this
    /// list once for `resetCursorRects` (every entry → pointing-
    /// hand) and once for `mouseDown` (first hit wins; switch on
    /// `action`). List / table / blockquote layouts have already
    /// flattened their inner-cell links into container-local coords
    /// during `make`, so they roll up here without further transform.
    var interactiveHits: [InteractiveHit] {
        var hits: [InteractiveHit] = []
        let links: [TextLayout.LinkHit]
        switch self {
        case .text(let l): links = l.links
        case .list(let l): links = l.links
        case .table(let l): links = l.links
        case .codeBlock(let l): links = l.links
        case .blockquote(let l): links = l.links
        case .image, .thematicBreak, .userBubble: links = []
        }
        hits.append(contentsOf: links.map {
            InteractiveHit(rect: $0.rect, action: .openURL($0.url))
        })
        switch self {
        case .userBubble(let l):
            if let r = l.chevronHitRect {
                hits.append(InteractiveHit(rect: r, action: .openUserBubbleSheet))
            }
        case .codeBlock(let l):
            if let r = l.copyHitRect {
                hits.append(InteractiveHit(rect: r, action: .copyText(l.code)))
            }
        default:
            break
        }
        return hits
    }

    /// Selection-facing API for this row, or `nil` for non-selectable
    /// kinds (image, thematic break). The selection coordinator and cell
    /// view consume only this — the underlying `TextLayout` /
    /// `TableLayout` / `ListLayout` type is encapsulated, so adding a new
    /// selectable kind needs no changes outside the new layout's own
    /// file.
    var selectionAdapter: SelectionAdapter? {
        switch self {
        case .text(let l): return l.selectionAdapter
        case .table(let l): return l.selectionAdapter
        case .list(let l): return l.selectionAdapter
        case .codeBlock(let l): return l.selectionAdapter
        case .blockquote(let l): return l.selectionAdapter
        case .image: return nil
        case .thematicBreak: return nil
        case .userBubble(let l): return l.selectionAdapter
        }
    }
}

import AppKit

/// Custom-drawn row cell. Holds a prepared `RowLayout`, draws it via
/// `override draw(_:)`.
///
/// Layer policy: `wantsLayer = true` + `.onSetNeedsDisplay`. The cached
/// layer bitmap is reused during scroll (zero `draw(_:)` calls), and AppKit
/// only re-issues `draw(_:)` after we mark `needsDisplay = true`.
///
/// ### Cursor + click dispatch
///
/// The cell is layout-agnostic for both. `RowLayout` exposes:
/// - `iBeamRect`: where the I-beam should show on hover (`nil` = full
///   cell `bounds`, the default for full-width text blocks; user-bubble
///   confines this to its right-aligned `bubbleRect` so the empty left
///   gutter keeps the default arrow).
/// - `interactiveHits`: list of `(rect, HitAction)` pairs covering URL
///   links, the user-bubble chevron, and the code-block copy button.
///
/// `resetCursorRects` registers I-beam over `iBeamRect` and pointing-
/// hand over each `interactiveHits` rect. AppKit handles hover cursor
/// swap automatically — no tracking area needed.
///
/// `mouseDown` walks the same `interactiveHits` list once, switches on
/// the matched `HitAction`, and falls through to selection-drag
/// forwarding when no hit is found. Adding a new in-cell control means
/// emitting another `InteractiveHit` from the relevant layout and
/// adding one switch arm here — no new `if case .xxx = layout` chains.
///
/// ### Selection
///
/// `selectedRange` is set by `Transcript2Coordinator` (read from
/// `Transcript2SelectionCoordinator`). Length-0 means no selection. The
/// highlight paints **before** the glyphs in `draw(_:)`, matching
/// `NSTextView`'s order so anti-aliased glyphs blend correctly against
/// the system selection background.
///
/// Color: `selectedTextBackgroundColor` (key window) /
/// `unemphasizedSelectedTextBackgroundColor` (resigned). Both are dynamic
/// colors that auto-resolve to the cell's effective appearance and the
/// system Accent Color, so we never construct a custom selection color.
///
/// `mouseDown` not consumed by a link is forwarded directly to the
/// enclosing `NSTableView` so its tracking-loop override can run text
/// selection. Using `nextResponder?.mouseDown` would route through
/// `NSTableRowView`, whose default mouseDown forwarding behavior is not
/// guaranteed; the explicit walk is deterministic.
final class BlockCellView: NSView {
    var layout: RowLayout? {
        didSet {
            needsDisplay = true
            // Cursor rects are cached by AppKit per-view; layout changes
            // (resize, content swap) invalidate those caches so the new
            // link rects take effect on the next mouse motion.
            window?.invalidateCursorRects(for: self)
        }
    }

    /// Set by `viewFor` so selection-driven repaints (window-key flip,
    /// drag updates) can be addressed back to this cell. Stale on a
    /// recycled cell until the next `viewFor` runs — that's fine because
    /// recycle-driven repaint goes through the same `viewFor`.
    var blockId: UUID?

    /// Set by `viewFor`. Used by mouseDown when a hit lands on a control
    /// belonging to the cell's layout (currently: user bubble chevron).
    /// Selection drag still walks to the enclosing `NSTableView` because
    /// AppKit's tracking loop owns that gesture — only cell-internal
    /// controls go through this reference.
    weak var coordinator: Transcript2Coordinator?

    /// Top padding contributed by the block's row (per-kind via
    /// `BlockStyle.blockPadding(for:)`). Drives `layoutOrigin.y` and
    /// selection rect offsetting. Set by `viewFor` alongside `layout`.
    var padTop: CGFloat = 0

    /// Current selection for this cell's block. `nil` = no selection.
    /// `didSet` triggers `needsDisplay` when the value actually changes;
    /// identical assignments are absorbed.
    var selection: SelectionRange? {
        didSet {
            if selection != oldValue {
                needsDisplay = true
            }
        }
    }

    /// Timestamp of the most recent copy click on this cell's code
    /// block, or `nil` when the button should display its idle
    /// (`doc.on.doc`) glyph. Set on click; cleared 1.5s later by a
    /// task that compares the timestamp before clearing (so a quick
    /// second click doesn't get its checkmark cut short by the first
    /// click's pending clear). Reset to `nil` on every `viewFor`
    /// reuse — the feedback is opportunistic, missing it on a
    /// scroll-recycled cell is fine.
    private var copiedAt: Date?

    /// Public reset hook for `viewFor` so a recycled cell never shows
    /// a stale checkmark on a different block.
    func resetCopiedFeedback() {
        if copiedAt != nil {
            copiedAt = nil
            needsDisplay = true
        }
    }

    override var isFlipped: Bool { true }
    override var wantsDefaultClipping: Bool { false }

    override init(frame frameRect: NSRect) {
        super.init(frame: frameRect)
        wantsLayer = true
        layerContentsRedrawPolicy = .onSetNeedsDisplay
    }

    required init?(coder: NSCoder) { fatalError() }

    private var layoutOrigin: CGPoint {
        CGPoint(
            x: BlockStyle.blockHorizontalPadding,
            y: padTop)
    }

    override func draw(_ dirtyRect: NSRect) {
        guard let layout, let ctx = NSGraphicsContext.current?.cgContext else { return }
        let origin = layoutOrigin

        // Backplate: opaque chrome that must paint *before* the
        // selection band so the highlight composites on top of (not
        // under) the card. No-op for everything except codeblock,
        // which has an opaque editor-canvas fill.
        layout.drawBackplate(in: ctx, origin: origin)

        // Selection highlight: under glyphs, matching NSTextView ordering.
        // The adapter projects (start, end) → layout-local rects; what
        // those rects mean (text glyph band / cell rectangle / 1×1 inner
        // band) is fully encapsulated inside the layout's adapter.
        if let selection, let adapter = layout.selectionAdapter {
            let rects = adapter.rects(selection.start, selection.end)
            if !rects.isEmpty {
                let color: NSColor = (window?.isKeyWindow == true)
                    ? .selectedTextBackgroundColor
                    : .unemphasizedSelectedTextBackgroundColor
                ctx.setFillColor(color.cgColor)
                for rect in rects {
                    // `integral` keeps the bg edges crisp on Retina at
                    // non-1× scale.
                    ctx.fill(rect.offsetBy(dx: origin.x, dy: origin.y).integral)
                }
            }
        }

        layout.draw(in: ctx, origin: origin)

        // Code-block copy glyph — layout owns the visual recipe
        // (symbol, tint, size); the cell only owns the trigger and
        // hands its transient `copiedAt` flag through as `checked`.
        if case .codeBlock(let l) = layout {
            l.drawCopyGlyph(in: ctx, origin: origin, checked: copiedAt != nil)
        }
    }

    // MARK: - Link interaction

    override func resetCursorRects() {
        super.resetCursorRects()
        guard let layout else { return }
        let origin = layoutOrigin
        // I-beam: over `iBeamRect` if the layout confines it
        // (user bubble), else the whole cell `bounds` to match
        // `NSTextView`'s "I-beam over full frame" behavior. Order
        // matters: when cursor rects overlap, the most-recently-
        // added wins, so pointing-hand rects registered below take
        // priority over the I-beam in their hot zones. Non-
        // selectable rows (image, thematic break) skip — they get
        // the default arrow.
        if layout.selectionAdapter != nil {
            let rect = layout.iBeamRect.map {
                $0.offsetBy(dx: origin.x, dy: origin.y)
            } ?? bounds
            addCursorRect(rect, cursor: .iBeam)
        }
        for hit in layout.interactiveHits {
            addCursorRect(hit.rect.offsetBy(dx: origin.x, dy: origin.y),
                          cursor: .pointingHand)
        }
    }

    override func mouseDown(with event: NSEvent) {
        if let action = hitAction(at: event) {
            switch action {
            case .openURL(let url):
                NSWorkspace.shared.open(url)
            case .openUserBubbleSheet:
                // The only well-defined exit point from AppKit-internal
                // interactions to SwiftUI, since `.sheet(item:)` lives
                // on the SwiftUI side. Selection-drag continues to stay
                // inside `Transcript2SelectionCoordinator`.
                if let id = blockId {
                    coordinator?.requestUserBubbleSheet(id: id)
                }
            case .copyText(let text):
                copyToPasteboard(text)
            }
            return
        }
        // Forward to the enclosing table so its tracking loop owns the
        // gesture (text-selection drag). Walk the superview chain rather
        // than relying on `nextResponder` — `NSTableRowView`'s default
        // mouseDown behavior isn't documented as forwarding.
        var v: NSView? = superview
        while let cur = v {
            if let table = cur as? NSTableView {
                table.mouseDown(with: event)
                return
            }
            v = cur.superview
        }
    }

    private func hitAction(at event: NSEvent) -> HitAction? {
        guard let layout else { return nil }
        let local = convert(event.locationInWindow, from: nil)
        let origin = layoutOrigin
        for hit in layout.interactiveHits {
            if hit.rect.offsetBy(dx: origin.x, dy: origin.y).contains(local) {
                return hit.action
            }
        }
        return nil
    }

    private func copyToPasteboard(_ text: String) {
        let pb = NSPasteboard.general
        pb.clearContents()
        pb.setString(text, forType: .string)

        // Visual feedback: swap idle → checkmark, schedule a swap back
        // 1.5s later. Stamp identity prevents a quick second click's
        // checkmark from being cut short by the first click's
        // pending clear.
        let stamp = Date()
        copiedAt = stamp
        needsDisplay = true
        Task { @MainActor [weak self] in
            try? await Task.sleep(nanoseconds: 1_500_000_000)
            guard let self, self.copiedAt == stamp else { return }
            self.copiedAt = nil
            self.needsDisplay = true
        }
    }
}

