import QuartzCore

/// 连续 tool_use 聚合 row —— 不论 tool kind,所有 assistant 消息只要 content
/// 全是 tool_use 就归这里。Header(title + chevron + shimmer)+ 展开态内嵌
/// N 条 child(per-tool dispatch 到 ``GroupChildRenderer``:Read 是 header-style
/// 文字行,其它是虚线占位框)。
///
/// `isActive = (entryIndex == entryCount - 1)` —— group 是 `entries.last` 即
/// 视作运行中。
///
/// 整 group(header + 所有 child)= **一个 NSTableView row**。toggle 展开
/// 走 `applyState` 的 `relayouted` 快路径,无 row insert/delete。子项**不**
/// 实现 `TranscriptComponent`,而是 ``GroupChildRenderer`` plug-in。
enum GroupComponent: TranscriptComponent {
    static let tag = "Group"

    // MARK: - Input / Content / Layout / State

    struct Input: @unchecked Sendable {
        let stableId: StableId
        /// 折叠态 active title —— 最后一条 tool 的进行时短语。
        let activeBriefTitle: String
        /// 展开态 active title —— 聚合进行时短语(`Reading 3 files · …`)。
        let activeAggregatedTitle: String
        /// 完成态 title —— 聚合过去时短语(`Read 3 files · …`)。
        let completedTitle: String
        let isActive: Bool
        /// 全部 tool_use,按 group item 顺序展平(单个 item 可能包含多个 tool_use)。
        let toolUses: [ToolUseEntry]

        struct ToolUseEntry: @unchecked Sendable {
            let toolUseId: String
            let tool: ToolUse
        }
    }

    struct Content: @unchecked Sendable {
        let isActive: Bool
        /// 三套 title 各自 prepare 一次 —— 切换不重 CT measure。
        let activeBrief: TitleMeasure
        let activeAggregated: TitleMeasure
        let completed: TitleMeasure
        /// per-child parsed payload,顺序 = ``Input.toolUses``。
        let children: [ChildEntry]

        struct ChildEntry: @unchecked Sendable {
            let toolUseId: String
            let content: GroupChildContent
        }

        struct TitleMeasure: @unchecked Sendable {
            let text: String
            let width: CGFloat
            let ascent: CGFloat
            let descent: CGFloat
        }

        /// 当前 (isActive, isExpanded) 下应展示的标题串 + 几何 —— layout 阶段
        /// 选用,render 阶段 sideCar 直接读。
        func pickTitle(isExpanded: Bool) -> TitleMeasure {
            switch (isActive, isExpanded) {
            case (true, false):  return activeBrief
            case (true, true):   return activeAggregated
            case (false, _):     return completed
            }
        }
    }

    struct Layout: HasHeight, Sendable {
        let content: Content
        /// 当前选中的 title,layout 时锁定。
        let titleText: String
        let titleRect: CGRect
        let chevronRect: CGRect
        let hitRect: CGRect
        /// 展开时各 child 的 frame;折叠时 [].
        let childFrames: [GroupChildFrame]
        let cachedHeight: CGFloat
        let cachedWidth: CGFloat
        let laidOutExpanded: Bool
    }

    struct State: Sendable {
        var isExpanded: Bool = false
        /// 留给未来富化 child 用 —— 第一步 Read 不带 substate。key = toolUseId,
        /// sparse map 默认空,绝大多数 child 不写入。
        var childStates: [String: ChildSubstate] = [:]

        static let `default` = State()
    }

    /// child 的 row-local state(Read 第一步无字段;Edit diff 展开等 future case
    /// 在这里加 enum case)。
    enum ChildSubstate: Sendable {
        case none
    }

    typealias SideCar = GroupSideCar

    // MARK: - Inputs

    nonisolated static func inputs(
        from entry: MessageEntry,
        entryIndex: Int,
        entryCount: Int
    ) -> [IdentifiedInput<Input>] {
        guard case .group(let group) = entry else { return [] }
        let isActive = (entryIndex == entryCount - 1)
        let stableId = StableId(entryId: group.id, locator: .whole)

        // 把整 group 的所有 tool_use 按 (item, blockOrder) 顺序展平。`tool.id` 在
        // generated 类型里是 `String?` —— 缺失场景(jsonl fixture 偶发) 用 toolUseId
        // 当兜底,group children 的相对顺序仍由展平顺序决定。
        var toolUses: [Input.ToolUseEntry] = []
        for item in group.items {
            for tool in item.toolUses {
                toolUses.append(.init(toolUseId: tool.id ?? "", tool: tool))
            }
        }

        return [IdentifiedInput(
            stableId: stableId,
            entryIndex: entryIndex,
            blockIndex: 0,
            input: Input(
                stableId: stableId,
                activeBriefTitle: group.activeTitle,
                activeAggregatedTitle: group.expandedActiveTitle,
                completedTitle: group.completedTitle,
                isActive: isActive,
                toolUses: toolUses))]
    }

    // MARK: - Prepare

    nonisolated static func prepare(
        _ input: Input,
        theme: TranscriptTheme
    ) -> Content {
        let active = measure(input.activeBriefTitle, theme: theme)
        let activeAgg = measure(input.activeAggregatedTitle, theme: theme)
        let completed = measure(input.completedTitle, theme: theme)
        let children = input.toolUses.map { entry in
            Content.ChildEntry(
                toolUseId: entry.toolUseId,
                content: GroupChildDispatch.parse(entry.tool, theme: theme))
        }
        return Content(
            isActive: input.isActive,
            activeBrief: active,
            activeAggregated: activeAgg,
            completed: completed,
            children: children)
    }

    nonisolated private static func measure(
        _ text: String, theme: TranscriptTheme
    ) -> Content.TitleMeasure {
        let attrs: [NSAttributedString.Key: Any] = [.font: theme.groupTitleFont]
        let str = NSAttributedString(string: text, attributes: attrs)
        let line = CTLineCreateWithAttributedString(str)
        var ascent: CGFloat = 0, descent: CGFloat = 0, leading: CGFloat = 0
        let width = CTLineGetTypographicBounds(line, &ascent, &descent, &leading)
        return Content.TitleMeasure(
            text: text,
            width: CGFloat(width),
            ascent: ascent,
            descent: descent)
    }

    nonisolated static func contentHash(
        _ input: Input,
        theme: TranscriptTheme
    ) -> Int {
        var h = Hasher()
        h.combine(input.activeBriefTitle)
        h.combine(input.activeAggregatedTitle)
        h.combine(input.completedTitle)
        h.combine(input.isActive)
        h.combine(input.toolUses.count)
        for entry in input.toolUses {
            h.combine(entry.toolUseId)
            h.combine(GroupChildDispatch.contentHash(entry.tool, theme: theme))
        }
        h.combine(theme.markdown.fingerprint)
        return h.finalize()
    }

    nonisolated static func initialState(for input: Input) -> State {
        .default
    }

    // MARK: - Layout

    nonisolated static func layout(
        _ content: Content,
        theme: TranscriptTheme,
        width: CGFloat,
        state: State
    ) -> Layout {
        geometry(content: content, theme: theme, width: width, state: state)
    }

    /// 快路径:width + content 未变,只 `isExpanded` 翻转 → 重选 title +
    /// 重算 childFrames + cachedHeight。
    nonisolated static func relayouted(
        _ layout: Layout,
        theme: TranscriptTheme,
        state: State
    ) -> Layout? {
        guard layout.laidOutExpanded != state.isExpanded else { return layout }
        return geometry(
            content: layout.content,
            theme: theme,
            width: layout.cachedWidth,
            state: state)
    }

    nonisolated private static func geometry(
        content: Content,
        theme: TranscriptTheme,
        width: CGFloat,
        state: State
    ) -> Layout {
        let hPad = theme.rowHorizontalPadding
        let headerTop = theme.rowVerticalPadding
        let headerH = theme.groupHeaderHeight
        let rowContentWidth = max(0, width - 2 * hPad)
        let chevronSize = theme.groupChevronDrawSize
        let gap = theme.groupChevronGap

        let title = content.pickTitle(isExpanded: state.isExpanded)

        // Title 占据文字宽度,但给 chevron + gap 留空间。
        let reservedForChevron = chevronSize + gap
        let titleMaxWidth = max(0, rowContentWidth - reservedForChevron)
        let titleWidth = min(title.width, titleMaxWidth)

        let titleH = title.ascent + title.descent
        let headerMidY = headerTop + headerH / 2
        let titleRect = CGRect(
            x: hPad,
            y: headerMidY - titleH / 2,
            width: titleWidth,
            height: titleH)

        // Chevron 视觉居中补偿 —— 同原实现。
        let font = theme.groupTitleFont
        let visualCompensation = max(0, (font.capHeight - font.xHeight) / 2)
        let chevronRect = CGRect(
            x: titleRect.maxX + gap,
            y: headerMidY - chevronSize / 2 + visualCompensation,
            width: chevronSize,
            height: chevronSize)

        let hitPad = theme.groupHitPadding
        let hitMinX = max(hPad, titleRect.minX - hitPad)
        let hitMaxX = min(hPad + rowContentWidth, chevronRect.maxX + hitPad)
        let hitRect = CGRect(
            x: hitMinX,
            y: headerTop,
            width: max(0, hitMaxX - hitMinX),
            height: headerH)

        // Children:gestalt 接近性下,header → first child 间距 = child ↔ child
        // 间距 = 4pt(``groupChildSpacing``)。最后一个 child 后接 row 自身的
        // bottom rowVerticalPadding,继而和下条 entry 的 top padding 加和成 ≥ 24pt
        // 视觉分隔(l0)。
        var childFrames: [GroupChildFrame] = []
        var totalHeight = headerTop + headerH
        if state.isExpanded && !content.children.isEmpty {
            var y = totalHeight + theme.groupChildSpacing
            for child in content.children {
                let frame = GroupChildDispatch.layout(
                    child.content,
                    x: hPad,
                    y: y,
                    width: rowContentWidth,
                    theme: theme)
                let h = GroupChildDispatch.height(frame)
                childFrames.append(frame)
                y += h + theme.groupChildSpacing
            }
            // 移除最后一次多加的 spacing(child 后面紧接 row vertical padding)。
            y -= theme.groupChildSpacing
            totalHeight = y
        }
        totalHeight += theme.rowVerticalPadding

        return Layout(
            content: content,
            titleText: title.text,
            titleRect: titleRect,
            chevronRect: chevronRect,
            hitRect: hitRect,
            childFrames: childFrames,
            cachedHeight: totalHeight,
            cachedWidth: width,
            laidOutExpanded: state.isExpanded)
    }

    // MARK: - Render

    @MainActor
    static func render(
        _ layout: Layout,
        state: State,
        theme: TranscriptTheme,
        sideCar: GroupSideCar,
        in ctx: CGContext,
        bounds: CGRect
    ) {
        // CGContext 路径只画 children;header(title / chevron / shimmer)由
        // SideCar 的 CALayer 完成。
        for (frame, child) in zip(layout.childFrames, layout.content.children) {
            GroupChildDispatch.draw(child.content, frame: frame, theme: theme, in: ctx)
        }

        sideCar.sync(
            title: layout.titleText,
            titleRect: layout.titleRect,
            chevronRect: layout.chevronRect,
            isActive: layout.content.isActive,
            isExpanded: state.isExpanded,
            theme: theme)
    }

    // MARK: - SideCar factory

    @MainActor
    static func makeSideCar(for content: Content) -> GroupSideCar {
        GroupSideCar()
    }

    // MARK: - Interactions

    @MainActor
    static func interactions(
        _ layout: Layout,
        state: State
    ) -> [Interaction<Self>] {
        let hit = layout.hitRect
        return [
            .custom(
                rect: hit,
                cursor: .pointingHand,
                handler: { ctx in
                    // 把 row-height 平滑插值 + chevron 旋转 + title fade 全部
                    // 包在同一个 NSAnimationContext 里 —— NSTableView 在
                    // `noteHeightOfRows` 时按当前 group 的 duration 走 builtin
                    // CABasicAnimation(高度从旧 cachedHeight 平滑到新值)。
                    NSAnimationContext.runAnimationGroup { animCtx in
                        animCtx.duration = ctx.theme.groupExpandDuration
                        animCtx.timingFunction = CAMediaTimingFunction(name: .easeInEaseOut)
                        var newState = ctx.currentState()
                        newState.isExpanded.toggle()
                        ctx.applyState(newState, animated: true)
                    }
                }),
            .hover(
                rect: hit,
                cursor: .pointingHand,
                onEnter: { ctx in ctx.sideCar().setHovered(true, theme: ctx.theme) },
                onExit:  { ctx in ctx.sideCar().setHovered(false, theme: ctx.theme) }),
        ]
    }
}

import AgentSDK
import AppKit
import CoreText

// MARK: - GroupChildRenderer protocol
//
// 每个 GroupChild 的 parse / layout / draw 实现 —— 整 group 才是一个 NSTableView
// row,child 只是 GroupComponent.Content / Layout / render 内部的子元素,**不**
// 实现 `TranscriptComponent`。
//
// 加新富化 tool = 新建一个 struct conform to GroupChildRenderer + 在
// `GroupChildContent` / `GroupChildFrame` 加 case + 在 `dispatch(_:)` 加 switch
// 分支。没有 SideCar、cache key、stableId 这些 row-level concerns。

protocol GroupChildRenderer {
    associatedtype Content: Sendable
    associatedtype Frame: Sendable

    static func parse(_ tool: ToolUse, theme: TranscriptTheme) -> Content
    static func contentHash(_ tool: ToolUse, theme: TranscriptTheme) -> Int

    /// `(x, y)` row-local 起点;width 是内容列宽度。
    static func layout(
        _ content: Content,
        x: CGFloat,
        y: CGFloat,
        width: CGFloat,
        theme: TranscriptTheme
    ) -> Frame

    static func height(_ frame: Frame) -> CGFloat

    @MainActor
    static func draw(
        _ content: Content,
        frame: Frame,
        theme: TranscriptTheme,
        in ctx: CGContext
    )
}

// MARK: - Discriminated union (dispatch storage)
//
// `GroupComponent.Content.children` 直接持 `[GroupChildContent]`,layout 阶段产出
// `[GroupChildFrame]`。union 的 case 即等价于 dispatch 表 —— 加新 renderer 时
// 在这两个 enum 各加一 case + 在下方 `dispatch` switch 加分支。

enum GroupChildContent: @unchecked Sendable {
    case read(ReadChildRenderer.Content)
    case placeholder(PlaceholderChildRenderer.Content)
}

enum GroupChildFrame: Sendable {
    case read(ReadChildRenderer.Frame)
    case placeholder(PlaceholderChildRenderer.Frame)
}

// MARK: - Dispatch helpers

enum GroupChildDispatch {

    /// 按 ToolUse 类型选择 renderer 并 parse 出 Content。
    nonisolated static func parse(_ tool: ToolUse, theme: TranscriptTheme) -> GroupChildContent {
        switch tool {
        case .Read:
            return .read(ReadChildRenderer.parse(tool, theme: theme))
        default:
            return .placeholder(PlaceholderChildRenderer.parse(tool, theme: theme))
        }
    }

    nonisolated static func contentHash(_ tool: ToolUse, theme: TranscriptTheme) -> Int {
        switch tool {
        case .Read:
            return ReadChildRenderer.contentHash(tool, theme: theme)
        default:
            return PlaceholderChildRenderer.contentHash(tool, theme: theme)
        }
    }

    nonisolated static func layout(
        _ content: GroupChildContent,
        x: CGFloat,
        y: CGFloat,
        width: CGFloat,
        theme: TranscriptTheme
    ) -> GroupChildFrame {
        switch content {
        case .read(let c):
            return .read(ReadChildRenderer.layout(c, x: x, y: y, width: width, theme: theme))
        case .placeholder(let c):
            return .placeholder(PlaceholderChildRenderer.layout(c, x: x, y: y, width: width, theme: theme))
        }
    }

    nonisolated static func height(_ frame: GroupChildFrame) -> CGFloat {
        switch frame {
        case .read(let f):        return ReadChildRenderer.height(f)
        case .placeholder(let f): return PlaceholderChildRenderer.height(f)
        }
    }

    @MainActor
    static func draw(
        _ content: GroupChildContent,
        frame: GroupChildFrame,
        theme: TranscriptTheme,
        in ctx: CGContext
    ) {
        switch (content, frame) {
        case (.read(let c), .read(let f)):
            ReadChildRenderer.draw(c, frame: f, theme: theme, in: ctx)
        case (.placeholder(let c), .placeholder(let f)):
            PlaceholderChildRenderer.draw(c, frame: f, theme: theme, in: ctx)
        default:
            // Content / Frame 必须同 case —— layout 由 parse 结果驱动,不可能错配。
            assertionFailure("GroupChildDispatch.draw: content/frame kind mismatch")
        }
    }
}

import AppKit
import QuartzCore

/// Group row 的 CA 侧 —— title / shimmer / chevron 三个 CALayer,挂
/// `rowView.layer`(AppKit 管 contentsScale,不用手管)。
///
/// 层级(下→上):
/// - `titleLayer` (CATextLayer):标题底色文字
/// - `shimmerLayer` (CAGradientLayer, mask = `shimmerMaskLayer`):active 态可见,
///   mask 把 gradient 裁到 title 字形,光带只扫文字
/// - `chevronLayer` (CAShapeLayer):2 段 `>` vector,`transform.rotation.z` 旋转
///
/// ## 居中列 offset
///
/// sublayer frame 用 "内容列局部坐标"(layout 算)。挂在全宽 `rowView.layer` 上,
/// `sync` 时把 frame.origin.x 加 `currentXOffset`(framework 每 render 前通过
/// `applyColumnXOffset` 注入)让 CA 路径和 CGContext 路径看到同一内容列起点。
///
/// ## 动画驱动
///
/// - rotation: `sync` 内部读 presentation 值 → toggle model → 在 disableActions
///   transaction **外** 显式 `CABasicAnimation`(避免被禁)
/// - title fade(active+collapsed ↔ active+expanded): `sync` 检测 string 变化时
///   先 `add(CATransition.fade)` 再改 string —— 必须在 disableActions transaction
///   外部
/// - shimmer: active 态启动,inactive 停止
@MainActor
final class GroupSideCar: RowSideCar {
    private let titleLayer = CATextLayer()
    private let shimmerLayer = CAGradientLayer()
    private let shimmerMaskLayer = CATextLayer()
    private let chevronLayer = CAShapeLayer()

    private var currentTitle: String = ""
    private var currentTitleRect: CGRect = .zero
    private var currentChevronRect: CGRect = .zero
    private var currentXOffset: CGFloat = 0
    private var isActive = false
    private var isExpanded = false
    private var isHovered = false
    private var isShimmerAnimating = false
    /// Sync 内部暂存 —— CATransaction 提交后再在外部 add 显式旋转动画。
    private var pendingRotation: (from: CGFloat, to: CGFloat)?

    init() {
        titleLayer.alignmentMode = .left
        titleLayer.truncationMode = .end
        titleLayer.isWrapped = false

        shimmerMaskLayer.alignmentMode = .left
        shimmerMaskLayer.truncationMode = .end
        shimmerMaskLayer.isWrapped = false
        shimmerMaskLayer.foregroundColor = NSColor.white.cgColor

        shimmerLayer.startPoint = CGPoint(x: -1, y: 0.5)
        shimmerLayer.endPoint = CGPoint(x: 0, y: 0.5)
        shimmerLayer.opacity = 0
        shimmerLayer.mask = shimmerMaskLayer

        chevronLayer.fillColor = nil
        chevronLayer.lineCap = .round
        chevronLayer.lineJoin = .round
        chevronLayer.lineWidth = 1.4
        chevronLayer.actions = ["position": NSNull(), "bounds": NSNull(), "frame": NSNull()]
    }

    nonisolated deinit {}

    // MARK: - RowSideCar lifecycle

    func sideCarDidMount(in rowLayer: CALayer) {
        let scale = rowLayer.contentsScale > 0 ? rowLayer.contentsScale : 2
        titleLayer.contentsScale = scale
        shimmerMaskLayer.contentsScale = scale
        chevronLayer.contentsScale = scale
        rowLayer.addSublayer(titleLayer)
        rowLayer.addSublayer(shimmerLayer)
        rowLayer.addSublayer(chevronLayer)
    }

    func sideCarWillUnmount(from rowLayer: CALayer) {
        shimmerLayer.removeAllAnimations()
        chevronLayer.removeAllAnimations()
        titleLayer.removeAllAnimations()
        titleLayer.removeFromSuperlayer()
        shimmerLayer.removeFromSuperlayer()
        chevronLayer.removeFromSuperlayer()
        isShimmerAnimating = false
    }

    func applyColumnXOffset(_ xOffset: CGFloat) {
        guard xOffset != currentXOffset else { return }
        currentXOffset = xOffset
        currentTitleRect = .zero
        currentChevronRect = .zero
    }

    // MARK: - Full sync

    func sync(
        title: String,
        titleRect: CGRect,
        chevronRect: CGRect,
        isActive active: Bool,
        isExpanded expanded: Bool,
        theme: TranscriptTheme
    ) {
        // Rotation pre-capture(在 model 改之前读 presentation 值)。
        let modelRotBefore = (chevronLayer.value(forKeyPath: "transform.rotation.z") as? CGFloat) ?? 0
        let presRotBefore = chevronLayer.presentation()?
            .value(forKeyPath: "transform.rotation.z") as? CGFloat
        let rotationFrom: CGFloat? = {
            guard expanded != isExpanded else { return nil }
            if let pres = presRotBefore { return pres }
            return modelRotBefore
        }()

        // Title 字符串变化 → 加 fade transition。在 disableActions transaction
        // 外部触发(transition 是 layer-level animation,会被 disableActions 屏蔽)。
        let titleStringChanged = (title != currentTitle && !currentTitle.isEmpty)

        CATransaction.begin()
        CATransaction.setDisableActions(true)

        let font = theme.groupTitleFont
        let fontSize = font.pointSize

        if title != currentTitle {
            titleLayer.string = title
            shimmerMaskLayer.string = title
            currentTitle = title
        }
        titleLayer.font = font
        titleLayer.fontSize = fontSize
        titleLayer.foregroundColor = titleColorForCurrentState(theme: theme).cgColor

        shimmerMaskLayer.font = font
        shimmerMaskLayer.fontSize = fontSize

        if titleRect != currentTitleRect {
            let titleFrame = titleRect.offsetBy(dx: currentXOffset, dy: 0)
            titleLayer.frame = titleFrame
            shimmerLayer.frame = titleFrame
            shimmerMaskLayer.frame = CGRect(origin: .zero, size: titleRect.size)
            currentTitleRect = titleRect
        }

        if chevronRect != currentChevronRect {
            chevronLayer.frame = chevronRect.offsetBy(dx: currentXOffset, dy: 0)
            chevronLayer.path = Self.chevronPath(in: CGRect(origin: .zero, size: chevronRect.size))
            currentChevronRect = chevronRect
        }
        chevronLayer.strokeColor = chevronColorForCurrentState(theme: theme).cgColor

        let hl = theme.groupShimmerHighlight.cgColor
        let clear = theme.groupShimmerHighlight.withAlphaComponent(0).cgColor
        shimmerLayer.colors = [clear, hl, clear]
        shimmerLayer.locations = [0, 0.5, 1]

        if active != isActive {
            shimmerLayer.opacity = active ? 1 : 0
            isActive = active
            if active {
                startShimmerAnimation(theme: theme)
            } else {
                stopShimmerAnimation()
            }
        } else if active && !isShimmerAnimating {
            shimmerLayer.opacity = 1
            startShimmerAnimation(theme: theme)
        }

        if let from = rotationFrom {
            let target: CGFloat = expanded ? (.pi / 2) : 0
            chevronLayer.setValue(target, forKeyPath: "transform.rotation.z")
            pendingRotation = (from: from, to: target)
            isExpanded = expanded
        }

        chevronLayer.opacity = Float(isHovered
            ? theme.groupChevronHoverAlpha
            : theme.groupChevronIdleAlpha)

        CATransaction.commit()

        // 显式动画在 disableActions 外部 add ——
        if let r = pendingRotation {
            pendingRotation = nil
            let anim = CABasicAnimation(keyPath: "transform.rotation.z")
            anim.duration = theme.groupChevronRotateDuration
            anim.timingFunction = CAMediaTimingFunction(name: .easeInEaseOut)
            anim.fromValue = r.from
            anim.toValue = r.to
            chevronLayer.add(anim, forKey: "rotate")
        }

        // Title fade ——(active+collapsed ↔ active+expanded 切换时聚合短语会变,
        // 直接换 string 突兀;用 CATransition 做平滑)。
        if titleStringChanged {
            let transition = CATransition()
            transition.type = .fade
            transition.duration = theme.groupTitleFadeDuration
            transition.timingFunction = CAMediaTimingFunction(name: .easeInEaseOut)
            titleLayer.add(transition, forKey: "titleFade")
            shimmerMaskLayer.add(transition, forKey: "titleFade")
        }
    }

    /// Hover 进入 / 离开 —— 不重 layout,只动画 chevron alpha + title 颜色。
    func setHovered(_ hovered: Bool, theme: TranscriptTheme) {
        guard hovered != isHovered else { return }
        isHovered = hovered

        let chevronTarget: Float = Float(hovered
            ? theme.groupChevronHoverAlpha
            : theme.groupChevronIdleAlpha)
        let chevronFrom = chevronLayer.presentation()?.opacity ?? chevronLayer.opacity
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        chevronLayer.opacity = chevronTarget
        CATransaction.commit()
        let chevronAnim = CABasicAnimation(keyPath: "opacity")
        chevronAnim.duration = theme.groupChevronFadeDuration
        chevronAnim.timingFunction = CAMediaTimingFunction(name: .easeOut)
        chevronAnim.fromValue = chevronFrom
        chevronAnim.toValue = chevronTarget
        chevronLayer.add(chevronAnim, forKey: "fade")

        let titleTargetColor = titleColorForCurrentState(theme: theme).cgColor
        let titleFromColor = titleLayer.presentation()?.foregroundColor
            ?? titleLayer.foregroundColor
        CATransaction.begin()
        CATransaction.setDisableActions(true)
        titleLayer.foregroundColor = titleTargetColor
        CATransaction.commit()
        let titleAnim = CABasicAnimation(keyPath: "foregroundColor")
        titleAnim.duration = theme.groupChevronFadeDuration
        titleAnim.timingFunction = CAMediaTimingFunction(name: .easeOut)
        titleAnim.fromValue = titleFromColor
        titleAnim.toValue = titleTargetColor
        titleLayer.add(titleAnim, forKey: "hoverColor")
    }

    private func titleColorForCurrentState(theme: TranscriptTheme) -> NSColor {
        isHovered ? NSColor.labelColor : theme.groupTitleColor
    }

    private func chevronColorForCurrentState(theme: TranscriptTheme) -> NSColor {
        isHovered ? NSColor.labelColor : theme.groupTitleColor
    }

    // MARK: - Chevron path

    private static func chevronPath(in rect: CGRect) -> CGPath {
        let path = CGMutablePath()
        let mid = CGPoint(x: rect.midX, y: rect.midY)
        let halfW = rect.width * 0.22
        let halfH = rect.height * 0.4
        path.move(to: CGPoint(x: mid.x - halfW, y: mid.y - halfH))
        path.addLine(to: CGPoint(x: mid.x + halfW, y: mid.y))
        path.addLine(to: CGPoint(x: mid.x - halfW, y: mid.y + halfH))
        return path
    }

    // MARK: - Shimmer animation

    private func startShimmerAnimation(theme: TranscriptTheme) {
        if isShimmerAnimating { return }
        isShimmerAnimating = true

        let band = theme.groupShimmerBandRatio
        let startAnim = CABasicAnimation(keyPath: "startPoint")
        startAnim.fromValue = NSValue(point: CGPoint(x: -band, y: 0.5))
        startAnim.toValue = NSValue(point: CGPoint(x: 1.0, y: 0.5))
        let endAnim = CABasicAnimation(keyPath: "endPoint")
        endAnim.fromValue = NSValue(point: CGPoint(x: 0.0, y: 0.5))
        endAnim.toValue = NSValue(point: CGPoint(x: 1.0 + band, y: 0.5))

        let group = CAAnimationGroup()
        group.animations = [startAnim, endAnim]
        group.duration = theme.groupShimmerDuration
        group.repeatCount = .infinity
        group.timingFunction = CAMediaTimingFunction(name: .linear)
        shimmerLayer.add(group, forKey: "shimmer")
    }

    private func stopShimmerAnimation() {
        shimmerLayer.removeAnimation(forKey: "shimmer")
        isShimmerAnimating = false
    }
}

import AppKit

/// Identifies the user bubble whose full text should be shown in a SwiftUI
/// modal sheet. `id` is the originating block's id; `text` is the
/// untruncated source. `Identifiable` so SwiftUI's `.sheet(item:)`
/// resolves presentation identity from this value alone.
struct UserBubbleSheetRequest: Identifiable, Equatable, Sendable {
    let id: UUID
    let text: String
}

/// Public, imperative API for `NativeTranscript2`. Three orthogonal channels:
///
/// 1. **Mutation** — `apply(_:scroll:)` accepts one or more `Change` values
///    (insert / remove / update) and a `ScrollState`. Granular only; no
///    diff, no `reloadData` escape hatch.
/// 2. **First-screen load** — `loadInitial(_:anchor:)` is the dedicated
///    cold-load path. Splits into a viewport-covering Phase 1 (sync, main)
///    and a Phase 2 (off-main layout, main-hop insert) so 10k-row initial
///    loads don't block the main thread.
/// 3. **Query** — read-only snapshot accessors.
///
/// `@MainActor`-isolated. Background producers must hop before calling.
@MainActor
@Observable
final class Transcript2Controller {
    enum Change: Sendable {
        /// Insert `blocks` after the block with id `after`. `after: nil`
        /// prepends (index 0). If `after` is non-nil but unknown (e.g. the
        /// anchor was removed), the change is a no-op — same posture as
        /// `.update` / `.remove` for unknown ids. To append, pass the
        /// current last block's id (or `nil` if empty).
        case insert(after: UUID?, _ blocks: [Block])
        /// Remove every block whose id is in `ids`. Unknown ids are ignored.
        case remove(ids: [UUID])
        /// Replace the kind of an existing block, preserving its id. No-op
        /// if the id is unknown.
        case update(id: UUID, kind: Block.Kind)
    }

    /// What the table should do with scroll position around an `apply`.
    enum ScrollState: Sendable, Equatable {
        case none
        /// After applying, scroll so the row with `id` is at the visual top.
        case top(id: UUID)
        /// After applying, scroll so the row with `id` is at the visual bottom.
        case bottom(id: UUID)
        /// Capture an anchor row's screen position before the change,
        /// recompute scroll afterwards so the same row stays visually in
        /// place. `Side` picks which row in the visible range to anchor on.
        case saveVisible(Side)

        enum Side: Sendable {
            case visualTop
            case visualBottom
        }
    }

    /// Where to land scroll on first-screen load.
    enum InitialAnchor: Sendable, Equatable {
        /// Default for chat: last block pinned to visual bottom.
        case bottom
        /// Pin the block with `id` to the visual top (jump to message /
        /// unread marker).
        case top(id: UUID)
        /// Pin the block with `id` to the visual bottom.
        case bottomTo(id: UUID)
    }

    /// Mirrored from the coordinator after every mutation so SwiftUI can
    /// observe count changes without reaching into AppKit state.
    private(set) var blockCount: Int = 0

    /// Pending request for the SwiftUI "show full user message" sheet,
    /// driven by chevron clicks inside `BlockCellView`. NSView-internal
    /// interactions (link click, selection drag, chevron tap) are normally
    /// AppKit-closed-loop; this is the one well-defined exit point because
    /// `.sheet(item:)` is a SwiftUI presentation primitive and has to live
    /// on the SwiftUI side. `NativeTranscript2View` binds against this
    /// field and clears it on dismiss.
    var pendingUserBubbleSheet: UserBubbleSheetRequest?

    /// Module-internal: handed to `NativeTranscript2View.makeCoordinator`.
    let coordinator: Transcript2Coordinator

    /// `syntaxEngine` enables async syntax highlighting for code blocks.
    /// Pass `nil` (the default) for previews / tests / hosts without an
    /// engine — code blocks render as plain monospaced text. Hosts that
    /// only have access to the engine through SwiftUI environment can
    /// late-bind via `attachSyntaxEngine(_:)`.
    init(syntaxEngine: SyntaxHighlightEngine? = nil) {
        coordinator = Transcript2Coordinator(syntaxEngine: syntaxEngine)
        coordinator.onBlockCountChanged = { [weak self] count in
            self?.blockCount = count
        }
        coordinator.onUserBubbleSheetRequested = { [weak self] id, text in
            self?.pendingUserBubbleSheet = UserBubbleSheetRequest(id: id, text: text)
        }
    }

    /// Late-bind a syntax engine. Pass-through to the coordinator. Safe
    /// to call repeatedly (idempotent on the same instance) and safe
    /// regardless of `loadInitial` ordering — the coordinator
    /// retroactively schedules already-installed blocks on first attach.
    func attachSyntaxEngine(_ engine: SyntaxHighlightEngine?) {
        coordinator.attachSyntaxEngine(engine)
    }

    // MARK: - Mutation

    /// Sync apply: layouts compute lazily on `heightOfRow` queries. Use for
    /// incremental updates (single message arrives, tool result fills in,
    /// user deletes one).
    func apply(_ changes: Change..., scroll: ScrollState = .none) {
        coordinator.apply(changes, scroll: scroll)
    }

    // MARK: - First-screen load

    /// Two-phase initial load. Phase 1 (sync) inserts a viewport-covering
    /// slice so the user sees correct content immediately. Phase 2 (off-main
    /// layout, main-hop insert) installs the rest with `.saveVisible` to
    /// keep Phase 1 visually fixed.
    ///
    /// The vertical scroller is push-hidden across both phases — Phase 1's
    /// scroll-to-anchor and Phase 2's insert+saveVisible both perturb the
    /// scroll origin, and the overlay scroller's auto-flash on
    /// `contentSize` change would otherwise paint a bouncing knob across
    /// the cold-load. Popped after Phase 1 (no-Phase-2 branch) or from
    /// Phase 2's completion (which `applyInBackground` guarantees to fire).
    func loadInitial(_ blocks: [Block], anchor: InitialAnchor = .bottom) {
        guard !blocks.isEmpty else { return }

        let width = coordinator.layoutWidth
        let viewportHeight = coordinator.viewportHeight
        guard width > 0, viewportHeight > 0 else {
            // Table not attached or zero-sized. Stash blocks; future attach
            // triggers reloadData. Scroll is meaningless without a table —
            // and so is the scroller-hidden token.
            coordinator.apply([.insert(after: coordinator.blockIds.last, blocks)], scroll: .none)
            return
        }

        let slice = Self.sliceForViewport(
            blocks: blocks, anchor: anchor,
            width: width, viewportHeight: viewportHeight)

        let phase1Scroll: ScrollState
        let phase2Side: ScrollState.Side
        switch anchor {
        case .bottom:
            phase1Scroll = .bottom(id: blocks[slice.viewportRange.upperBound - 1].id)
            phase2Side = .visualBottom
        case .top(let id):
            phase1Scroll = .top(id: id)
            phase2Side = .visualTop
        case .bottomTo(let id):
            phase1Scroll = .bottom(id: id)
            phase2Side = .visualBottom
        }

        let viewportBatch = Array(blocks[slice.viewportRange])
        let above = Array(blocks[..<slice.viewportRange.lowerBound])
        let below =
            slice.viewportRange.upperBound < blocks.count
            ? Array(blocks[slice.viewportRange.upperBound...])
            : []

        coordinator.pushScrollerHidden()

        // Phase 1 — viewport batch, sync. heightOfRow lazy-computes layouts
        // for the visible rows; cost is bounded by viewport size.
        coordinator.apply(
            [.insert(after: coordinator.blockIds.last, viewportBatch)],
            scroll: phase1Scroll)

        // Phase 2 — the rest, off-main layout. ID-based anchors mean
        // ordering between the two inserts no longer matters: each anchor
        // resolves at apply-time independently of the other change.
        var phase2: [Change] = []
        if !below.isEmpty {
            phase2.append(.insert(after: viewportBatch.last?.id, below))
        }
        if !above.isEmpty {
            phase2.append(.insert(after: nil, above))
        }
        if phase2.isEmpty {
            coordinator.popScrollerHidden()
        } else {
            coordinator.applyInBackground(phase2, scroll: .saveVisible(phase2Side)) {
                [weak coordinator] in coordinator?.popScrollerHidden()
            }
        }
    }

    // MARK: - Query

    var blockIds: [UUID] { coordinator.blockIds }

    // MARK: - Slicing (private)

    private struct Slice {
        /// Range into the original `blocks` array covering the viewport.
        let viewportRange: Range<Int>
    }

    /// Walks `blocks` from the anchor outward, accumulating row heights
    /// until viewport is covered. Pure: only reads `Coordinator.makeLayout`
    /// (a `nonisolated static` function); does not mutate cache.
    private static func sliceForViewport(
        blocks: [Block],
        anchor: InitialAnchor,
        width: CGFloat,
        viewportHeight: CGFloat
    ) -> Slice {
        func rowHeight(_ block: Block) -> CGFloat {
            let pad = BlockStyle.blockPadding(for: block.kind)
            return Transcript2Coordinator.makeLayout(for: block, width: width).totalHeight
                + pad.top + pad.bottom
        }

        switch anchor {
        case .bottom:
            var height: CGFloat = 0
            var first = blocks.count
            for i in stride(from: blocks.count - 1, through: 0, by: -1) {
                height += rowHeight(blocks[i])
                first = i
                if height >= viewportHeight { break }
            }
            return Slice(viewportRange: first..<blocks.count)

        case .top(let id):
            guard let anchorIdx = blocks.firstIndex(where: { $0.id == id }) else {
                return sliceForViewport(
                    blocks: blocks, anchor: .bottom,
                    width: width, viewportHeight: viewportHeight)
            }
            var height: CGFloat = 0
            var last = anchorIdx
            for i in anchorIdx..<blocks.count {
                height += rowHeight(blocks[i])
                last = i
                if height >= viewportHeight { break }
            }
            return Slice(viewportRange: anchorIdx..<last + 1)

        case .bottomTo(let id):
            guard let anchorIdx = blocks.firstIndex(where: { $0.id == id }) else {
                return sliceForViewport(
                    blocks: blocks, anchor: .bottom,
                    width: width, viewportHeight: viewportHeight)
            }
            var height: CGFloat = 0
            var first = anchorIdx
            for i in stride(from: anchorIdx, through: 0, by: -1) {
                height += rowHeight(blocks[i])
                first = i
                if height >= viewportHeight { break }
            }
            return Slice(viewportRange: first..<anchorIdx + 1)
        }
    }
}

import AgentSDK
import AppKit
import CoreText

/// 兜底 child renderer —— 未富化 tool kind 在 group 展开态画一条虚线占位框。
/// 形态参照 standalone `PlaceholderComponent`(同高、同 dash pattern、同圆角),
/// 视觉上让"非富化"和独立 tool 行保持一致。
enum PlaceholderChildRenderer: GroupChildRenderer {

    struct Content: @unchecked Sendable {
        let label: String
        let labelLine: CTLine
        let labelAscent: CGFloat
        let labelDescent: CGFloat
    }

    struct Frame: Sendable {
        let rect: CGRect
    }

    nonisolated static func parse(_ tool: ToolUse, theme: TranscriptTheme) -> Content {
        let label = "[Tool: \(tool.caseName)]"
        let attrs: [NSAttributedString.Key: Any] = [
            .font: theme.placeholderTextFont,
            .foregroundColor: NSColor.secondaryLabelColor,
        ]
        let str = NSAttributedString(string: label, attributes: attrs)
        let line = CTLineCreateWithAttributedString(str)
        var ascent: CGFloat = 0, descent: CGFloat = 0, leading: CGFloat = 0
        _ = CTLineGetTypographicBounds(line, &ascent, &descent, &leading)
        return Content(
            label: label,
            labelLine: line,
            labelAscent: ascent,
            labelDescent: descent)
    }

    nonisolated static func contentHash(_ tool: ToolUse, theme: TranscriptTheme) -> Int {
        var h = Hasher()
        h.combine("placeholder")
        h.combine(tool.caseName)
        return h.finalize()
    }

    nonisolated static func layout(
        _ content: Content,
        x: CGFloat,
        y: CGFloat,
        width: CGFloat,
        theme: TranscriptTheme
    ) -> Frame {
        Frame(rect: CGRect(x: x, y: y, width: width, height: theme.groupChildPlaceholderHeight))
    }

    nonisolated static func height(_ frame: Frame) -> CGFloat {
        frame.rect.height
    }

    @MainActor
    static func draw(
        _ content: Content,
        frame: Frame,
        theme: TranscriptTheme,
        in ctx: CGContext
    ) {
        let outer = frame.rect
        // Inset 取 placeholderVerticalInset(顶/底)— 跟独立 placeholder 视觉对齐。
        let r = outer.insetBy(dx: 0, dy: theme.placeholderVerticalInset)

        ctx.saveGState()
        ctx.setStrokeColor(NSColor.tertiaryLabelColor.cgColor)
        ctx.setLineWidth(1)
        ctx.setLineDash(phase: 0, lengths: theme.placeholderLineDashPattern)
        let path = CGPath(
            roundedRect: r,
            cornerWidth: theme.placeholderCornerRadius,
            cornerHeight: theme.placeholderCornerRadius,
            transform: nil)
        ctx.addPath(path)
        ctx.strokePath()
        ctx.restoreGState()

        let baselineY = r.midY + (content.labelAscent - content.labelDescent) / 2
        ctx.saveGState()
        ctx.textMatrix = CGAffineTransform(scaleX: 1, y: -1)
        ctx.textPosition = CGPoint(x: r.minX + 12, y: baselineY)
        CTLineDraw(content.labelLine, ctx)
        ctx.restoreGState()
    }
}

import AgentSDK
import AppKit
import CoreText

/// 富化 Read child —— 展开态用 group header 同款字体 / 颜色画一行
/// title("Read foo.swift" / "Reading foo.swift"),没有 chevron、没有交互。
/// 第一步刻意不做内嵌再展开。
enum ReadChildRenderer: GroupChildRenderer {

    struct Content: @unchecked Sendable {
        /// 标题文字 —— 展开态 child 用 completed 形式(`Read foo.swift`)。
        /// 选词理由见 ``readTitle(_:)``。
        let title: String
        let titleLine: CTLine
        let titleWidth: CGFloat
        let titleAscent: CGFloat
        let titleDescent: CGFloat
    }

    struct Frame: Sendable {
        /// row-local 全宽 frame —— 高度 = `groupChildHeaderHeight`。
        let rect: CGRect
        /// title 在 frame 内的 baseline 位置(相对 rect.origin)。
        let titleRect: CGRect
    }

    /// `parse` 只接受 `.Read`;非 Read 类型走 `PlaceholderChildRenderer` 兜底。
    /// 调用方(`GroupChildDispatch.parse`)在 switch 里保证传 Read。这里再防御性
    /// 处理一次,避免 force-unwrap 在 fixture / 单测里炸。
    nonisolated static func parse(_ tool: ToolUse, theme: TranscriptTheme) -> Content {
        let title = readTitle(tool)
        let attrs: [NSAttributedString.Key: Any] = [.font: theme.groupTitleFont]
        let str = NSAttributedString(string: title, attributes: attrs)
        let line = CTLineCreateWithAttributedString(str)
        var ascent: CGFloat = 0, descent: CGFloat = 0, leading: CGFloat = 0
        let width = CTLineGetTypographicBounds(line, &ascent, &descent, &leading)
        return Content(
            title: title,
            titleLine: line,
            titleWidth: CGFloat(width),
            titleAscent: ascent,
            titleDescent: descent)
    }

    nonisolated static func contentHash(_ tool: ToolUse, theme: TranscriptTheme) -> Int {
        var h = Hasher()
        h.combine("read")
        h.combine(readTitle(tool))
        return h.finalize()
    }

    nonisolated static func layout(
        _ content: Content,
        x: CGFloat,
        y: CGFloat,
        width: CGFloat,
        theme: TranscriptTheme
    ) -> Frame {
        let h = theme.groupChildHeaderHeight
        let outer = CGRect(x: x, y: y, width: width, height: h)
        // 文字垂直居中——跟 group header 同算法,baseline 居中行高。
        let titleH = content.titleAscent + content.titleDescent
        let clampedWidth = min(content.titleWidth, width)
        let titleRect = CGRect(
            x: outer.minX,
            y: outer.midY - titleH / 2,
            width: clampedWidth,
            height: titleH)
        return Frame(rect: outer, titleRect: titleRect)
    }

    nonisolated static func height(_ frame: Frame) -> CGFloat {
        frame.rect.height
    }

    @MainActor
    static func draw(
        _ content: Content,
        frame: Frame,
        theme: TranscriptTheme,
        in ctx: CGContext
    ) {
        let titleRect = frame.titleRect
        let baselineY = titleRect.maxY - content.titleDescent

        // 重新构造带 foregroundColor 的 CTLine —— parse 阶段只塞了 font,
        // 颜色在这里加(避免 CTLine 缓存进 cache 时锁死颜色,无法跟随 theme)。
        let attrs: [NSAttributedString.Key: Any] = [
            .font: theme.groupTitleFont,
            .foregroundColor: theme.groupTitleColor,
        ]
        let line = CTLineCreateWithAttributedString(
            NSAttributedString(string: content.title, attributes: attrs))

        ctx.saveGState()
        ctx.textMatrix = CGAffineTransform(scaleX: 1, y: -1)
        ctx.textPosition = CGPoint(x: titleRect.minX, y: baselineY)
        CTLineDraw(line, ctx)
        ctx.restoreGState()
    }

    /// `Reading foo.swift`(active) / `Read foo.swift`(completed)。
    /// active vs completed 由 GroupComponent 整体 isActive 驱动 ——
    /// `parse` 拿到的 ToolUse 自身没 active 标记,我们靠 `activeFragment` /
    /// `completedFragment` 两个 string 各 cache 一份,通过 contentHash 包进
    /// GroupComponent.contentHash 让 cache 自动 invalidate。
    /// 第一步 MVP:Read child 在 active group 用 activeFragment,在 completed
    /// group 用 completedFragment —— 这个判断在 GroupChildDispatch 拿不到
    /// isActive,所以 Read child 直接展示 completedFragment(展开态都是历史
    /// child,active 的 last 在 header 里已经体现)。
    private nonisolated static func readTitle(_ tool: ToolUse) -> String {
        // 展开态 child 永远展示 completed 形式 —— 原因:展开后用户已知道在
        // active group(header shimmer + active title 在画),child 列表是
        // "已经/正在被处理的文件清单",过去式更易扫读;active 进行时由
        // header 反映即可。
        tool.completedFragment ?? "[\(tool.caseName)]"
    }
}

import AppKit

/// Immutable thematic-break layout — pure function of `maxWidth`.
///
/// Renders as a single horizontal hairline spanning the row's content
/// width. No selectable region (no glyphs to select), no link, no
/// internal payload — `RowLayout` exposes a `nil` `selectionAdapter`
/// for this kind so the cell skips the I-beam cursor and selection
/// painting paths entirely.
struct ThematicBreakLayout: Sendable {
    let totalHeight: CGFloat
    let measuredWidth: CGFloat

    nonisolated static func make(maxWidth: CGFloat) -> ThematicBreakLayout {
        ThematicBreakLayout(
            totalHeight: BlockStyle.thematicBreakHeight,
            measuredWidth: max(0, maxWidth))
    }

    /// Draws the hairline at vertical center of `(origin, totalHeight)`.
    /// `origin` is the layout's top-left in view coords (y-down, flipped
    /// table view).
    func draw(in ctx: CGContext, origin: CGPoint) {
        guard measuredWidth > 0 else { return }
        ctx.saveGState()
        ctx.setFillColor(BlockStyle.thematicBreakColor.cgColor)
        ctx.fill(CGRect(
            x: origin.x,
            y: origin.y + (totalHeight - BlockStyle.thematicBreakHeight) / 2,
            width: measuredWidth,
            height: BlockStyle.thematicBreakHeight))
        ctx.restoreGState()
    }
}

import AppKit
import SwiftUI

/// SwiftUI entry point. Mounts `Transcript2ScrollView` (containing a
/// `NSTableView` driven by `Transcript2Coordinator`) and binds the user
/// bubble's "show full message" sheet.
///
/// The view takes a caller-owned `Transcript2Controller` — there is no
/// `[Block]` `State` parameter. Callers mutate transcript content
/// imperatively via `controller.apply(.insert / .remove / .update)` for
/// incremental changes, or `controller.loadInitial(_:)` for the cold-load
/// path. SwiftUI's role is reduced to mounting the AppKit view, wiring
/// the existing coordinator into it, and presenting the sheet driven by
/// `controller.pendingUserBubbleSheet`; `updateNSView` is a no-op.
struct NativeTranscript2View: View {
    @Bindable var controller: Transcript2Controller
    /// Async syntax highlighter, sourced from the SwiftUI environment so
    /// every host (chat, demo, stress) gets the same shared engine
    /// without explicit plumbing. `nil` is the legitimate "no host
    /// engine" mode — code blocks then render plain. Late-binds via
    /// `controller.attachSyntaxEngine` once `body` resolves the env.
    @Environment(\.syntaxEngine) private var syntaxEngine

    var body: some View {
        Transcript2NSViewBridge(controller: controller)
            .sheet(item: $controller.pendingUserBubbleSheet) { request in
                UserBubbleSheetView(text: request.text)
            }
            .task(id: ObjectIdentifier(controller)) {
                // Idempotent re-attach. Survives `controller` swap (rare,
                // but `.task(id:)` makes the dependency explicit) and
                // engine swap (env updates don't normally happen, but the
                // controller's `attachSyntaxEngine` handles a re-set
                // gracefully via the per-block generation guard).
                controller.attachSyntaxEngine(syntaxEngine)
            }
    }
}

/// Modal view for a user bubble's full text. Selection / copy come for
/// free via `Text.textSelection(.enabled)`; the dismiss button lives in
/// the bottom-right and binds the default action key (Return).
struct UserBubbleSheetView: View {
    let text: String
    @Environment(\.dismiss) private var dismiss

    var body: some View {
        VStack(spacing: 0) {
            ScrollView {
                Text(text)
                    .textSelection(.enabled)
                    .font(.body)
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .padding(20)
            }
            Divider()
            HStack {
                Spacer()
                Button("Done") { dismiss() }
                    .keyboardShortcut(.defaultAction)
            }
            .padding(12)
        }
        .frame(minWidth: 520, idealWidth: 720, maxWidth: 960,
               minHeight: 360, idealHeight: 540, maxHeight: 800)
    }
}

/// `NSViewRepresentable` half — kept private so the SwiftUI-side sheet
/// modifier composes cleanly above it.
private struct Transcript2NSViewBridge: NSViewRepresentable {
    let controller: Transcript2Controller

    func makeCoordinator() -> Transcript2Coordinator { controller.coordinator }

    func makeNSView(context: Context) -> Transcript2ScrollView {
        let scroll = Transcript2ScrollView()
        scroll.hasVerticalScroller = true
        scroll.hasHorizontalScroller = false
        scroll.drawsBackground = false
        scroll.borderType = .noBorder
        scroll.autohidesScrollers = true
        scroll.scrollerStyle = .overlay
        scroll.wantsLayer = true
        scroll.layerContentsRedrawPolicy = .never
        scroll.automaticallyAdjustsContentInsets = false
        scroll.contentInsets = NSEdgeInsets(top: 12, left: 0, bottom: 12, right: 0)
        scroll.contentView = Transcript2ClipView()

        let table = Transcript2TableView()
        table.headerView = nil
        table.backgroundColor = .clear
        table.style = .plain
        table.selectionHighlightStyle = .none
        table.intercellSpacing = NSSize(width: 0, height: 0)
        table.usesAutomaticRowHeights = false
        table.gridStyleMask = []
        table.allowsColumnResizing = false
        table.allowsColumnReordering = false
        table.allowsColumnSelection = false
        table.allowsMultipleSelection = false
        table.allowsEmptySelection = true

        let column = NSTableColumn(identifier: NSUserInterfaceItemIdentifier("col"))
        column.resizingMask = .autoresizingMask
        column.minWidth = 0
        column.maxWidth = .greatestFiniteMagnitude
        table.addTableColumn(column)

        let coordinator = context.coordinator
        table.dataSource = coordinator
        table.delegate = coordinator
        table.postsFrameChangedNotifications = true
        NotificationCenter.default.addObserver(
            coordinator,
            selector: #selector(Transcript2Coordinator.tableFrameDidChange(_:)),
            name: NSView.frameDidChangeNotification, object: table)

        coordinator.tableView = table
        table.coordinator = coordinator
        scroll.documentView = table
        return scroll
    }

    func updateNSView(_ nsView: Transcript2ScrollView, context: Context) {
        // No-op. Content is pushed via `controller.apply(_:)`, not pulled
        // from a SwiftUI snapshot.
    }

    static func dismantleNSView(_ nsView: Transcript2ScrollView,
                                coordinator: Transcript2Coordinator) {
        NotificationCenter.default.removeObserver(coordinator)
    }
}

