import SwiftUI

/// v2 根视图：Sidebar v2 + 只读 ChatHistoryView。
/// 选中态本地持有，不走 AppState / ChatRouter。
struct RootView2: View {
    @State private var selectedSessionId: String?
    @State private var columnVisibility: NavigationSplitViewVisibility = .all

    var body: some View {
        NavigationSplitView(columnVisibility: $columnVisibility) {
            SidebarView2(selection: $selectedSessionId)
                .navigationSplitViewColumnWidth(min: 220, ideal: 260, max: 350)
        } detail: {
            if selectedSessionId == SidebarView2.transcriptDemoTag {
                TranscriptDemoView()
                    .frame(minWidth: 400)
            } else if selectedSessionId == SidebarView2.transcriptStressTag {
                TranscriptStressView()
                    .frame(minWidth: 400)
            } else if let sid = selectedSessionId {
                // `.id(sid)` 必须在**调用点**: 让 ChatHistoryView 整个 struct
                // 随 sessionId 重建,`@State handle` 跟着 reset。放在 body 内
                // 的 Group 上无效(只换 Group 子树,@State 保留跨 session)。
                ChatHistoryView(sessionId: sid)
                    .id(sid)
                    .frame(minWidth: 400)
            } else {
                Color.clear
                    .frame(minWidth: 400)
            }
        }
        .frame(minWidth: 800, minHeight: 480)
    }
}

import AppKit

/// Immutable blockquote layout — pure function of `([InlineNode], maxWidth)`.
///
/// **No container chrome**: just a left accent bar and indented text.
/// Matches the prior renderer's blockquote treatment (and Slack /
/// Discord / GitHub conventions): a quote is a margin annotation, not
/// a standalone container, so adding a bg fill or rounded corner gives
/// it more visual weight than its semantic role deserves.
///
/// `@unchecked Sendable` for the same reason as `TextLayout` — the
/// embedded layout owns `CTLine` references.
struct BlockquoteLayout: @unchecked Sendable {
    let text: TextLayout
    /// Left bar in layout-local coords (y-down). Height matches the
    /// inner text height so the bar starts and ends with the glyphs,
    /// not with the row pad.
    let barRect: CGRect
    /// Top-left of the text region — equals
    /// `(blockquoteBarWidth + blockquoteBarGap, 0)`.
    let textOriginInLayout: CGPoint

    let totalHeight: CGFloat
    let measuredWidth: CGFloat

    /// Link hit zones already projected into layout-local coords.
    var links: [TextLayout.LinkHit] {
        text.links.map { hit in
            TextLayout.LinkHit(
                rect: hit.rect.offsetBy(dx: textOriginInLayout.x,
                                        dy: textOriginInLayout.y),
                url: hit.url)
        }
    }

    nonisolated static func make(inlines: [InlineNode], maxWidth: CGFloat) -> BlockquoteLayout {
        guard maxWidth > 0 else {
            return BlockquoteLayout(
                text: .empty,
                barRect: .zero,
                textOriginInLayout: .zero,
                totalHeight: 0,
                measuredWidth: 0)
        }
        let leftInset = BlockStyle.blockquoteBarWidth + BlockStyle.blockquoteBarGap
        let textMaxWidth = max(1, maxWidth - leftInset)
        let attributed = BlockStyle.paragraphAttributed(inlines: inlines)
        let text = TextLayout.make(attributed: attributed, maxWidth: textMaxWidth)

        let textOrigin = CGPoint(x: leftInset, y: 0)
        let bar = CGRect(
            x: 0, y: 0,
            width: BlockStyle.blockquoteBarWidth,
            height: text.totalHeight)

        return BlockquoteLayout(
            text: text,
            barRect: bar,
            textOriginInLayout: textOrigin,
            totalHeight: text.totalHeight,
            measuredWidth: maxWidth)
    }

    // MARK: - Selection adapter

    /// Wraps the inner `TextLayout`'s adapter, offsetting hit-test input
    /// and selection rects by the text region's origin.
    var selectionAdapter: SelectionAdapter {
        let inner = text.selectionAdapter
        let offset = textOriginInLayout
        return SelectionAdapter(
            fullRange: inner.fullRange,
            unitRange: inner.unitRange,
            hitTest: { p in
                inner.hitTest(CGPoint(x: p.x - offset.x, y: p.y - offset.y))
            },
            rects: { a, b in
                inner.rects(a, b).map {
                    $0.offsetBy(dx: offset.x, dy: offset.y)
                }
            },
            string: inner.string,
            wordBoundary: inner.wordBoundary)
    }

    // MARK: - Draw

    func draw(in ctx: CGContext, origin: CGPoint) {
        // 1) Left accent bar — `cornerWidth: 1` is anti-aliasing cleanup,
        //    not a visible round (matches the prior renderer's value).
        ctx.saveGState()
        let bar = barRect.offsetBy(dx: origin.x, dy: origin.y)
        let path = CGPath(
            roundedRect: bar, cornerWidth: 1, cornerHeight: 1, transform: nil)
        ctx.setFillColor(BlockStyle.blockquoteBarColor.cgColor)
        ctx.addPath(path)
        ctx.fillPath()
        ctx.restoreGState()

        // 2) Text — same color and styling as a regular paragraph.
        text.draw(in: ctx, origin: CGPoint(
            x: origin.x + textOriginInLayout.x,
            y: origin.y + textOriginInLayout.y))
    }
}

import AppKit

/// Concrete, typed selection position. Each layout produces only its own
/// case and consumes only its own case via the `SelectionAdapter` it
/// hands out — the cases exist as a tagged union so heterogeneous
/// layouts can store / move positions through a single dictionary
/// without `Any` / `AnyHashable` / existential erasure.
///
/// **Discipline:** `Transcript2SelectionCoordinator` and `BlockCellView`
/// never `switch` on this enum. They round-trip values through the
/// adapter that produced them. `if case` inside a layout's adapter
/// closures is acceptable (and is the layout's own self-check that the
/// position came from the right source).
enum LayoutPosition: Equatable, Hashable {
    case text(char: Int)
    case cell(row: Int, col: Int, char: Int)
    case listItem(paragraph: Int, char: Int)
}

/// Two `LayoutPosition`s describing one block's current selection. Order
/// is unconstrained — `SelectionAdapter.rects` / `string` normalize as
/// needed.
struct SelectionRange: Equatable {
    let start: LayoutPosition
    let end: LayoutPosition
}

/// Layout's selection-facing API. A struct of typed function values
/// captured over the (immutable) layout instance — no protocol, no
/// `any`, no associatedtype.
///
/// `Transcript2SelectionCoordinator` and `BlockCellView` interact with
/// the layout exclusively through this adapter, so the layout's internal
/// selection topology (1-D char index for text, 2-D `(row, col, char)`
/// for table) stays encapsulated behind `LayoutPosition` and never leaks
/// into the coordinator's algorithm.
struct SelectionAdapter {
    /// Anchor / cursor pair representing "the entire layout selected."
    /// Used by Cmd+A and as the row-edge endpoints in multi-row drag
    /// (top-row → end-of-layout, start-of-layout → bottom-row, middle
    /// rows full-select).
    let fullRange: SelectionRange

    /// Range covering "the unit at this position" — drives triple-click
    /// whole-unit selection. Distinct from `fullRange` because a layout's
    /// top-level full range and its triple-click target diverge for
    /// composite layouts: a table's `fullRange` is the whole table
    /// (Cmd+A target), but `unitRange` at a click point is just that one
    /// cell. For text, the two coincide (block == unit). For list, the
    /// unit is the paragraph the position lives in.
    let unitRange: (LayoutPosition) -> SelectionRange

    /// Layout-local point → opaque position. Out-of-bounds points clamp
    /// to the nearest edge so the caller always gets a defined landing.
    let hitTest: (CGPoint) -> LayoutPosition

    /// Layout-local highlight rects spanning the (`a`, `b`) pair. Order
    /// of arguments doesn't matter — the adapter normalizes internally.
    let rects: (_ a: LayoutPosition, _ b: LayoutPosition) -> [CGRect]

    /// Plain-text representation of the selection, with U+2028 inline
    /// line-separators normalized to `\n` for paste targets that don't
    /// render them. Per-block joiner (`\n\n` between blocks) is the
    /// caller's responsibility.
    let string: (_ a: LayoutPosition, _ b: LayoutPosition) -> String

    /// Word-boundary expansion at a click point — drives double-click
    /// word selection and byWord drag snap. Returns `nil` at positions
    /// where the layout has no word concept (empty layout, etc.).
    let wordBoundary: (LayoutPosition) -> SelectionRange?
}

import AppKit
import CoreText

/// Immutable Core Text layout — pure function of (attributed string, max width).
///
/// Coordinate system: y grows downward (matches NSTableView's flipped row coords).
/// `lineOrigins[i].y` is the baseline distance from the top of the layout.
///
/// `@unchecked Sendable`: Swift's type system can't see that `CTLine` is
/// thread-safe. Apple's Core Text Programming Guide documents `CTLine` as
/// immutable / safe to share across threads — we promise not to mutate the
/// `[CTLine]` after construction.
///
/// Performance (Apple Silicon, system font, width=600, Swift `-O`; see
/// `cctermTests/NativeTranscript2/TextLayoutBenchmarkTests.swift`):
///
/// | text                | make/100ch | draw warm/100ch |
/// |---------------------|-----------:|----------------:|
/// | ASCII paragraph 14pt (steady) | ~15–20μs  | ~12μs |
/// | CJK   paragraph 14pt (steady) | ~100μs    | ~34μs |
/// | ASCII heading 22pt           | ~15μs     | ~27μs |
///
/// Both are O(n). CJK is 5–8× slower than ASCII at every step (heavier shaping).
/// `make` cost is ≥95% in `CTTypesetterCreateWithAttributedString` + per-line
/// `CTTypesetterSuggestLineBreak`; the per-line `CTTypesetterCreateLine` +
/// `CTLineGetTypographicBounds` are <5%. **Don't write a height-only fast path
/// that drops `CTLine` creation — it saves nothing.** The make/draw split pays
/// off only for long text + repeat draws (e.g. 10k-char paragraph: draw is
/// 0.21× of make); short text the split is roughly neutral.
/// Draw cost is insensitive to layout instance — CG glyph cache is
/// process-global and warms in <1 frame.
///
/// ### Decoration extraction
///
/// `CTLineDraw` only paints glyphs — it does **not** honor
/// `.backgroundColor` and does **not** respond to `.link` clicks. Both
/// require a post-typeset scan over runs to compute screen-space rects:
/// inline-code backgrounds (drawn by `draw(in:origin:)` itself), and link
/// hot zones (consumed by the cell for hit-testing + cursor). Done once at
/// `make` time so layout reuse benefits include the decoration data.
struct TextLayout: @unchecked Sendable {
    /// Source attributed string. Held so the layout can produce its own
    /// `SelectionAdapter` (byWord snap and copy-string) without callers
    /// having to keep / re-derive it. NSAttributedString is reference-
    /// shared, so the only cost is a refcount bump.
    let attributed: NSAttributedString
    let lines: [CTLine]
    let lineOrigins: [CGPoint]
    /// Per-line ascent/descent. Used by selection rect generation and by
    /// hit-testing to find the line whose vertical band contains a point.
    /// Promoted from a local `make`-time variable into stored state because
    /// recomputing `CTLineGetTypographicBounds` on every selection update
    /// during a drag is wasted work.
    let lineMetrics: [LineMetrics]
    let totalHeight: CGFloat
    let measuredWidth: CGFloat
    /// Inline code backgrounds in layout-local coords (y down, top-left).
    /// Tight to the line's ascent/descent — no leading — so multi-line
    /// paragraphs keep their bg boxes inside each line's vertical band
    /// instead of bleeding into the next line.
    let codeBackgrounds: [CGRect]
    /// Link hit zones in layout-local coords. Multi-line links produce one
    /// rect per line.
    let links: [LinkHit]

    struct LineMetrics: Sendable {
        let ascent: CGFloat
        let descent: CGFloat
    }

    struct LinkHit: Sendable {
        let rect: CGRect
        let url: URL
    }

    /// Total typeset character count. Equal to the source attributed
    /// string's length when `make` ran to completion (typesetter
    /// consumed all characters).
    var length: Int {
        guard let last = lines.last else { return 0 }

import AppKit

// MARK: - Key types (file-scope so conformance stays nonisolated)

/// Where inside a block highlight tokens belong. One block kind may emit
/// multiple scopes (a future diff block emits one per hunk × side);
/// adding a scope is two lines (enum case + switch arm in
/// `Transcript2HighlightStorage.requests(for:)`).
///
/// Declared at file scope so the `Hashable` / `Sendable` conformance is
/// nonisolated — the storage class is `@MainActor`, but the off-main
/// `makeLayout` path looks up `[Key: ...]` snapshots without crossing the
/// actor boundary, so the key/value types must work outside MainActor.
enum Transcript2HighlightScope: Hashable, Sendable {
    case codeBlock
    // case diffOld(hunk: Int)
    // case diffNew(hunk: Int)
}

struct Transcript2HighlightKey: Hashable, Sendable {
    let blockId: UUID
    let scope: Transcript2HighlightScope
}

// MARK: - Storage

/// Per-block, async-filled side data backing syntax highlighting (and any
/// future highlight-shaped derivative — diff hunks, inline annotations,
/// etc.). Storage is keyed by `(blockId, Scope)` so a single block can
/// carry multiple highlight regions (e.g. diff old/new sides) without
/// extra dicts.
///
/// ### Lifecycle
///
/// - `schedule(_:)` — called from `Coordinator.applyStructuralChange` for
///   `.insert` and `.update`. Looks at `block.kind`, emits the highlight
///   requests for that kind, fires a single `engine.highlightBatch` over
///   them, writes the results back, and notifies via `onDidFill(blockId)`
///   so the coordinator can reload the row.
/// - `drop(blockId:)` — called for `.remove` and at the head of `.update`.
///   Wipes every entry whose id matches and bumps the generation counter
///   so an in-flight schedule for the same id no longer commits.
/// - `snapshot()` — read-only copy of the tokens map. Used by the
///   coordinator's off-main precompute paths (`applyInBackground`,
///   `refillLayoutCache`) so the detached task can call `makeLayout`
///   without crossing the actor boundary mid-loop.
///
/// ### Generation guard
///
/// `inflightGen[id]` is bumped on every `schedule` and on every `drop`.
/// A task captures the generation at start; if it drifted by completion,
/// the writeback is skipped. This prevents an older highlight (kicked
/// before an `.update` replaced the code) from clobbering a newer one
/// that finished sooner.
@MainActor
final class Transcript2HighlightStorage {
    typealias Scope = Transcript2HighlightScope
    typealias Key = Transcript2HighlightKey

    /// Settable so SwiftUI hosts can inject `\.syntaxEngine` from the

input.old_string:
        /// User-side message rendered as a right-aligned bubble. Long text
        /// auto-truncates with a tail "…" + a `>` chevron whose click
        /// surfaces the full message in a SwiftUI sheet (presentation
        /// concerns belong on the SwiftUI side; in-cell rendering stays
        /// stateless). Short messages render in full with no chevron.
        case userBubble(text: String)
    }
}

input.new_string:
        /// User-side message rendered as a right-aligned bubble. Long text
        /// auto-truncates with a tail "…" + a `>` chevron whose click
        /// surfaces the full message in a SwiftUI sheet (presentation
        /// concerns belong on the SwiftUI side; in-cell rendering stays
        /// stateless). Short messages render in full with no chevron.
        case userBubble(text: String)
        /// A run of tool invocations rendered as one collapsible row:
        /// header (title + chevron) on top, an optional list of per-tool
        /// children below. Fold state is **not** in the kind — it lives
        /// in `Transcript2Coordinator.expandedGroups` keyed by block id —
        /// so a content `.update` (e.g. a tool result lands) preserves
        /// whether the user had expanded this group. The whole group is
        /// a single NSTableView row, so toggling fold is `O(1)`: evict
        /// one cache entry, push the new layout to the existing cell,
        /// `noteHeightOfRows` on one row. Sibling rows below slide via
        /// AppKit's implicit row animation; layer-cached cells don't
        /// redraw.
        case toolGroup(ToolGroupBlock)
    }
}

/// Render-ready group data. Three pre-computed titles cover the (active /
/// completed) × (collapsed / expanded) state space — picked at layout
/// time so a fold toggle never recomputes the title string. `children`
/// is the flattened list of tool entries in display order; an empty
/// array is legitimate (group with no surfaced children draws header
/// only).
