///      in this MVP:
///        - `read` → single muted text line (header chrome style)
///        - `placeholder` → dashed rounded box with a `[Tool: …]` label
///
/// Fold state is **not** stored in the layout — it's an input to
/// `make`. The owning coordinator keeps a `Set<UUID>` of expanded
/// block ids and re-issues `make(... isExpanded: …)` when toggling.
/// This keeps the layout a pure value while still letting toggle take
/// the `O(1)` cache-evict + 1-row-relayout path.
///
/// `@unchecked Sendable` for the same reason as `TextLayout` /
/// `BlockquoteLayout`: embedded `CTLine` references.
struct ToolGroupLayout: @unchecked Sendable {
    let isActive: Bool
    let isExpanded: Bool

    let titleText: String
    let titleLine: CTLine
    let titleAscent: CGFloat
    let titleDescent: CGFloat
    /// Title region in layout-local coords (y-down). Width is clamped
    /// to leave room for the chevron + gap on the right.
    let titleRect: CGRect
    /// Chevron region in layout-local coords. Glyph painted by `draw`
    /// adapts to `isExpanded` to flip between `>` and `v`.
    let chevronRect: CGRect
    /// Combined header click target — title + chevron + a small hit
    /// pad on either side. Spans the full header band height so the
    /// pointing-hand cursor is comfortable to land on.
    let hitRect: CGRect

    let children: [ChildLayout]

    let totalHeight: CGFloat
    let measuredWidth: CGFloat

    /// Per-child rendered geometry. The discriminated union models the
    /// dispatch table — adding a richer renderer (e.g. `case diff(...)`)
    /// is one new case + one new arm in `makeChild` / `draw`.
    enum ChildLayout: @unchecked Sendable {
        case read(Read)
        case placeholder(Placeholder)

        struct Read: @unchecked Sendable {
            let titleLine: CTLine
            let titleAscent: CGFloat
            let titleDescent: CGFloat
            /// Outer band in layout-local coords. Height ==
            /// `toolGroupReadChildHeight`; spacing-around lives in the
            /// parent layout's stack math, not here.
            let frame: CGRect
            /// Title baseline rect inside `frame`. Vertically centered
            /// on `frame.midY` so the muted text reads as a continuation
            /// of the header band's typographic rhythm.
            let titleRect: CGRect
        }

        struct Placeholder: @unchecked Sendable {
            let labelLine: CTLine
            let labelAscent: CGFloat
            let labelDescent: CGFloat
            /// Outer dashed-box frame in layout-local coords.
            let frame: CGRect
        }
    }

    // MARK: - Make

    nonisolated static func make(
        block: ToolGroupBlock, isExpanded: Bool, maxWidth: CGFloat
    ) -> ToolGroupLayout {
        let titleText = pickTitle(for: block, isExpanded: isExpanded)

        // Empty-width short circuit — keeps the type valid but renders
        // nothing. Same posture as `BlockquoteLayout.make`'s
        // `maxWidth > 0` guard.
        guard maxWidth > 0 else {
            let emptyLine = CTLineCreateWithAttributedString(
                NSAttributedString(string: titleText))
            return ToolGroupLayout(
                isActive: block.isActive,
                isExpanded: isExpanded,
                titleText: titleText,
                titleLine: emptyLine,
                titleAscent: 0, titleDescent: 0,
                titleRect: .zero,
                chevronRect: .zero,
                hitRect: .zero,
                children: [],
                totalHeight: 0,
                measuredWidth: 0)
        }

        // 1) Header — title.
        let titleAttrs: [NSAttributedString.Key: Any] = [
            .font: BlockStyle.toolGroupTitleFont,
            .foregroundColor: BlockStyle.toolGroupTitleColor,
        ]
        let titleAttributed = NSAttributedString(
            string: titleText, attributes: titleAttrs)
        let titleLine = CTLineCreateWithAttributedString(titleAttributed)
        var ascent: CGFloat = 0, descent: CGFloat = 0, leading: CGFloat = 0
        let measuredTitleW = CGFloat(CTLineGetTypographicBounds(
            titleLine, &ascent, &descent, &leading))

        let chevronSize = BlockStyle.toolGroupChevronSize
        let chevronGap = BlockStyle.toolGroupChevronGap
        let reservedForChevron = chevronSize + chevronGap
        let titleMaxW = max(0, maxWidth - reservedForChevron)
        let titleW = min(measuredTitleW, titleMaxW)

        let headerH = BlockStyle.toolGroupHeaderHeight
        let titleH = ascent + descent
        let headerMidY = headerH / 2
        let titleRect = CGRect(
            x: 0, y: headerMidY - titleH / 2,
            width: titleW, height: titleH)

        // Chevron's optical center: typographic centerline sits below
        // the cap-line for sans-serif fonts, so a chevron centered on
        // the `headerMidY` reads as slightly low next to the title.
        // Nudge upward by `(capHeight - xHeight) / 2`, matching the
        // trick the prior `GroupComponent` used.
        let titleFont = BlockStyle.toolGroupTitleFont
        let visualCompensation = max(0, (titleFont.capHeight - titleFont.xHeight) / 2)
        let chevronRect = CGRect(
            x: titleRect.maxX + chevronGap,
            y: headerMidY - chevronSize / 2 + visualCompensation,
            width: chevronSize, height: chevronSize)

        // Hit zone — full header band height + a small pad on the
        // horizontal axis so the chevron has comfortable hit area.
        let hitPad = BlockStyle.toolGroupHitPadding
        let hitMinX = max(0, titleRect.minX - hitPad)
        let hitMaxX = min(maxWidth, chevronRect.maxX + hitPad)
        let hitRect = CGRect(
            x: hitMinX, y: 0,
            width: max(0, hitMaxX - hitMinX),
            height: headerH)

        // 2) Children — only laid out when expanded. Collapsed groups
        // skip per-child CT measurement entirely so the cold path stays
        // cheap; first expand pays the measurement cost, the result
        // sits in the layout cache until invalidated.
        var totalHeight = headerH
        var children: [ChildLayout] = []
        if isExpanded && !block.children.isEmpty {
            children.reserveCapacity(block.children.count)
            var y = totalHeight + BlockStyle.toolGroupChildSpacing
            for child in block.children {
                let layout = makeChild(child, x: 0, y: y, width: maxWidth)
                let frame = layout.frame
                children.append(layout)
                y = frame.maxY + BlockStyle.toolGroupChildSpacing
            }
            // Drop the trailing spacing — block-level vertical padding
            // covers the gap to the next row.
            totalHeight = y - BlockStyle.toolGroupChildSpacing
        }

        return ToolGroupLayout(
            isActive: block.isActive,
            isExpanded: isExpanded,
            titleText: titleText,
            titleLine: titleLine,
            titleAscent: ascent,
            titleDescent: descent,
            titleRect: titleRect,
            chevronRect: chevronRect,
            hitRect: hitRect,
            children: children,
            totalHeight: totalHeight,
            measuredWidth: maxWidth)
    }

    nonisolated private static func pickTitle(
        for block: ToolGroupBlock, isExpanded: Bool
    ) -> String {
        switch (block.isActive, isExpanded) {
        case (true, false): return block.activeBriefTitle
        case (true, true):  return block.activeAggregatedTitle
        case (false, _):    return block.completedTitle
        }
    }

    nonisolated private static func makeChild(
        _ child: ToolGroupChild, x: CGFloat, y: CGFloat, width: CGFloat
    ) -> ChildLayout {
        switch child {
        case .read(let title):
            let attrs: [NSAttributedString.Key: Any] = [
                .font: BlockStyle.toolGroupTitleFont,
                .foregroundColor: BlockStyle.toolGroupTitleColor,
            ]
            let line = CTLineCreateWithAttributedString(
                NSAttributedString(string: title, attributes: attrs))
            var ascent: CGFloat = 0, descent: CGFloat = 0, leading: CGFloat = 0
            let measured = CGFloat(CTLineGetTypographicBounds(line, &ascent, &descent, &leading))
            let h = BlockStyle.toolGroupReadChildHeight
            let outer = CGRect(x: x, y: y, width: width, height: h)
            let titleH = ascent + descent
            let titleRect = CGRect(
                x: outer.minX,
                y: outer.midY - titleH / 2,
                width: min(measured, width),
                height: titleH)
            return .read(.init(
                titleLine: line,
                titleAscent: ascent, titleDescent: descent,
                frame: outer, titleRect: titleRect))

        case .placeholder(let label):
            let attrs: [NSAttributedString.Key: Any] = [
                .font: BlockStyle.toolGroupPlaceholderTextFont,
                .foregroundColor: BlockStyle.toolGroupPlaceholderForegroundColor,
            ]
            let line = CTLineCreateWithAttributedString(
                NSAttributedString(string: label, attributes: attrs))
            var ascent: CGFloat = 0, descent: CGFloat = 0, leading: CGFloat = 0
            _ = CTLineGetTypographicBounds(line, &ascent, &descent, &leading)
            let h = BlockStyle.toolGroupPlaceholderHeight
            let outer = CGRect(x: x, y: y, width: width, height: h)
            return .placeholder(.init(
                labelLine: line,
                labelAscent: ascent, labelDescent: descent,
                frame: outer))
        }
    }

    // MARK: - Interactive hits

    /// One header click → toggle. Children are non-interactive in this
    /// MVP. Selection isn't supported either (`RowLayout.selectionAdapter`
    /// returns `nil` for `.toolGroup`).
    var interactiveHits: [InteractiveHit] {
        guard hitRect.width > 0, hitRect.height > 0 else { return [] }
        return [InteractiveHit(rect: hitRect, action: .toggleToolGroup)]
    }

    // MARK: - Draw

    func draw(in ctx: CGContext, origin: CGPoint) {
        // 1) Header title — baseline math is identical to the other
        // CT-based layouts: in a flipped y-down view, the visible top
        // sits at `titleRect.minY`, baseline = top + ascent =
        // titleRect.maxY - descent.
        ctx.saveGState()
        ctx.textMatrix = CGAffineTransform(scaleX: 1, y: -1)
        ctx.textPosition = CGPoint(
            x: origin.x + titleRect.minX,
            y: origin.y + titleRect.maxY - titleDescent)
        CTLineDraw(titleLine, ctx)
        ctx.restoreGState()

        // 2) Chevron — `>` collapsed, `v` expanded. Static (no rotation
        // animation in MVP); the row-height animation carries the
        // perceptual weight of the toggle.
        drawChevron(in: ctx, origin: origin)

        // 3) Children (when expanded).
        for child in children {
            switch child {
            case .read(let c): drawReadChild(c, in: ctx, origin: origin)
            case .placeholder(let c): drawPlaceholderChild(c, in: ctx, origin: origin)
            }
        }
    }

    private func drawChevron(in ctx: CGContext, origin: CGPoint) {
        guard chevronRect.width > 0, chevronRect.height > 0 else { return }
        let rect = chevronRect.offsetBy(dx: origin.x, dy: origin.y)
        let cx = rect.midX
        let cy = rect.midY
        // Tuned per-axis half-extents — same proportions the prior
        // `GroupSideCar` used (`halfW = 0.22 · width`,
        // `halfH = 0.4 · height`). Those numbers come from the
        // chevron-in-square baseline; expanded swaps the axes so the
        // glyph rotates 90° without any matrix transform.
        let halfW = rect.width * 0.22
        let halfH = rect.height * 0.4
        let path = CGMutablePath()
        if isExpanded {
            // `v` — apex at bottom-mid. Same proportions, axes swapped.
            path.move(to: CGPoint(x: cx - halfH, y: cy - halfW))
            path.addLine(to: CGPoint(x: cx,        y: cy + halfW))
            path.addLine(to: CGPoint(x: cx + halfH, y: cy - halfW))
        } else {
            // `>` — apex at right-mid.
            path.move(to: CGPoint(x: cx - halfW, y: cy - halfH))
            path.addLine(to: CGPoint(x: cx + halfW, y: cy))
            path.addLine(to: CGPoint(x: cx - halfW, y: cy + halfH))
        }
        ctx.saveGState()
        ctx.setStrokeColor(BlockStyle.toolGroupTitleColor.cgColor)
        ctx.setLineWidth(1.4)
        ctx.setLineCap(.round)
        ctx.setLineJoin(.round)
        ctx.addPath(path)
        ctx.strokePath()
        ctx.restoreGState()
    }

    private func drawReadChild(
        _ c: ChildLayout.Read, in ctx: CGContext, origin: CGPoint
    ) {
        ctx.saveGState()
        ctx.textMatrix = CGAffineTransform(scaleX: 1, y: -1)
        ctx.textPosition = CGPoint(
            x: origin.x + c.titleRect.minX,
            y: origin.y + c.titleRect.maxY - c.titleDescent)
        CTLineDraw(c.titleLine, ctx)
        ctx.restoreGState()
    }

    private func drawPlaceholderChild(
        _ c: ChildLayout.Placeholder, in ctx: CGContext, origin: CGPoint
    ) {
        let outer = c.frame.offsetBy(dx: origin.x, dy: origin.y)
        // 1.5pt vertical inset so the dashed stroke doesn't sit flush
        // against the row's nominal child band.
        let r = outer.insetBy(dx: 0, dy: 1.5)

        ctx.saveGState()
        ctx.setStrokeColor(BlockStyle.toolGroupPlaceholderStrokeColor.cgColor)
        ctx.setLineWidth(1)
        ctx.setLineDash(phase: 0, lengths: BlockStyle.toolGroupPlaceholderDashPattern)
        let radius = BlockStyle.toolGroupPlaceholderCornerRadius
        let path = CGPath(
            roundedRect: r,
            cornerWidth: radius, cornerHeight: radius, transform: nil)
        ctx.addPath(path)
        ctx.strokePath()
        ctx.restoreGState()

        let baselineY = r.midY + (c.labelAscent - c.labelDescent) / 2
        ctx.saveGState()
        ctx.textMatrix = CGAffineTransform(scaleX: 1, y: -1)
        ctx.textPosition = CGPoint(
            x: r.minX + BlockStyle.toolGroupPlaceholderTextLeftInset,
            y: baselineY)
        CTLineDraw(c.labelLine, ctx)
        ctx.restoreGState()
    }
}

// MARK: - ChildLayout frame helper

extension ToolGroupLayout.ChildLayout {
    /// Outer frame in layout-local coords. Drives the parent's stack
    /// math — `make` advances `y` past `frame.maxY` after each child.
    var frame: CGRect {
        switch self {
        case .read(let c): return c.frame
        case .placeholder(let c): return c.frame
        }
    }
}

