import AppKit
import CoreText

/// "Read" child — single muted text line in the group's title style.
/// No expand affordance, no copy button — the goal is just to expose
/// the file name to scan-reading after the group is expanded. Drawing
/// is a single `CTLineDraw` call.
///
/// Geometry note: the outer band is sized to a fixed
/// `toolGroupReadChildHeight`; the title rect is vertically centered
/// inside it. Stack math (advancing `y` between siblings) lives on the
/// owning `ToolGroupLayout`, not here, so individual children stay
/// position-independent.
///
/// `@unchecked Sendable` — same reason as the other CT-bearing
/// layouts: `CTLine` is documented as immutable / thread-safe.
struct ReadChildLayout: @unchecked Sendable {
    let titleLine: CTLine
    let titleAscent: CGFloat
    let titleDescent: CGFloat
    /// Outer band in layout-local coords (y-down). Height ==
    /// `BlockStyle.toolGroupReadChildHeight`. The owning
    /// `ToolGroupLayout` advances its stack `y` past `frame.maxY`
    /// after each child is laid out.
    let frame: CGRect
    /// Title baseline rect inside `frame`. Vertically centered on
    /// `frame.midY` so the muted text reads as a continuation of the
    /// header band's typographic rhythm.
    let titleRect: CGRect

    nonisolated static func make(
        title: String, x: CGFloat, y: CGFloat, width: CGFloat
    ) -> ReadChildLayout {
        let attrs: [NSAttributedString.Key: Any] = [
            .font: BlockStyle.toolGroupTitleFont,
            .foregroundColor: BlockStyle.toolGroupTitleColor,
        ]
        let line = CTLineCreateWithAttributedString(
            NSAttributedString(string: title, attributes: attrs))
        var ascent: CGFloat = 0, descent: CGFloat = 0, leading: CGFloat = 0
        let measured = CGFloat(CTLineGetTypographicBounds(
            line, &ascent, &descent, &leading))

        let h = BlockStyle.toolGroupReadChildHeight
        let outer = CGRect(x: x, y: y, width: width, height: h)
        let titleH = ascent + descent
        let titleRect = CGRect(
            x: outer.minX,
            y: outer.midY - titleH / 2,
            width: min(measured, width),
            height: titleH)
        return ReadChildLayout(
            titleLine: line,
            titleAscent: ascent, titleDescent: descent,
            frame: outer, titleRect: titleRect)
    }

    func draw(in ctx: CGContext, origin: CGPoint) {
        // Baseline math identical to the other CT-based layouts: in a
        // flipped y-down view the visible top sits at `titleRect.minY`,
        // baseline = top + ascent = titleRect.maxY - descent.
        ctx.saveGState()
        ctx.textMatrix = CGAffineTransform(scaleX: 1, y: -1)
        ctx.textPosition = CGPoint(
            x: origin.x + titleRect.minX,
            y: origin.y + titleRect.maxY - titleDescent)
        CTLineDraw(titleLine, ctx)
        ctx.restoreGState()
    }
}

