import AppKit
import CoreText

/// Generic dashed-rect placeholder for tools without a rich renderer
/// yet. Draws a 1pt rounded dashed border + a left-anchored label
/// (`[Tool: Bash]` etc.) — visually signals "not yet rich-rendered"
/// without dropping the entry from the group entirely. Same posture
/// the prior `PlaceholderChildRenderer` took.
///
/// `@unchecked Sendable` — same `CTLine` carve-out as the other
/// layouts.
struct PlaceholderChildLayout: @unchecked Sendable {
    let labelLine: CTLine
    let labelAscent: CGFloat
    let labelDescent: CGFloat
    /// Outer dashed-box frame in layout-local coords (y-down).
    let frame: CGRect

    nonisolated static func make(
        label: String, x: CGFloat, y: CGFloat, width: CGFloat
    ) -> PlaceholderChildLayout {
        let attrs: [NSAttributedString.Key: Any] = [
            .font: BlockStyle.toolGroupPlaceholderTextFont,
            .foregroundColor: BlockStyle.toolGroupPlaceholderForegroundColor,
        ]
        let line = CTLineCreateWithAttributedString(
            NSAttributedString(string: label, attributes: attrs))
        var ascent: CGFloat = 0, descent: CGFloat = 0, leading: CGFloat = 0
        _ = CTLineGetTypographicBounds(line, &ascent, &descent, &leading)

        let h = BlockStyle.toolGroupPlaceholderHeight
        let outer = CGRect(x: x, y: y, width: width, height: h)
        return PlaceholderChildLayout(
            labelLine: line,
            labelAscent: ascent, labelDescent: descent,
            frame: outer)
    }

    func draw(in ctx: CGContext, origin: CGPoint) {
        let outer = frame.offsetBy(dx: origin.x, dy: origin.y)
        // 1.5pt vertical inset so the dashed stroke doesn't sit flush
        // against the row's nominal child band; lets the dashes stay
        // inside the spacing zone the parent layout reserved.
        let r = outer.insetBy(dx: 0, dy: 1.5)

        ctx.saveGState()
        ctx.setStrokeColor(BlockStyle.toolGroupPlaceholderStrokeColor.cgColor)
        ctx.setLineWidth(1)
        ctx.setLineDash(phase: 0, lengths: BlockStyle.toolGroupPlaceholderDashPattern)
        let radius = BlockStyle.toolGroupPlaceholderCornerRadius
        let path = CGPath(
            roundedRect: r,
            cornerWidth: radius, cornerHeight: radius, transform: nil)
        ctx.addPath(path)
        ctx.strokePath()
        ctx.restoreGState()

        // Label baseline — visually centered on the dashed box's midY,
        // not on its frame's midY, so the small vertical inset above
        // doesn't drift the text off-center.
        let baselineY = r.midY + (labelAscent - labelDescent) / 2
        ctx.saveGState()
        ctx.textMatrix = CGAffineTransform(scaleX: 1, y: -1)
        ctx.textPosition = CGPoint(
            x: r.minX + BlockStyle.toolGroupPlaceholderTextLeftInset,
            y: baselineY)
        CTLineDraw(labelLine, ctx)
        ctx.restoreGState()
    }
}

