import AppKit

/// Type-erased dispatch over the per-tool child layouts owned by
/// `ToolGroupLayout`. The discriminated union *is* the dispatch table
/// — adding a richer renderer (e.g. `case diff(DiffChildLayout)`) is:
///
///   1. Add a new file in this folder with the layout struct (+ its
///      `make` and `draw`).
///   2. Add a new case here — and one arm to `make` / `draw` / `frame`.
///   3. Add a new case to `ToolGroupChild` (the input IR enum in
///      `Block.swift`) and route it through `make` below.
///
/// No protocol on purpose: the surface (`make` / `draw` / `frame`) is
/// uniform but trivial, and the upstream (`ToolGroupChild`) only ever
/// switches once into the layout side, so a closed enum keeps both
/// sides exhaustive without the ceremony of an `any ChildLayout` box.
///
/// `@unchecked Sendable` is inherited from each child layout's CT
/// carve-out.
enum ToolGroupChildLayout: @unchecked Sendable {
    case read(ReadChildLayout)
    case placeholder(PlaceholderChildLayout)

    /// Outer frame in layout-local coords. Drives the parent's stack
    /// math — `ToolGroupLayout.make` advances `y` past `frame.maxY`
    /// after each child.
    var frame: CGRect {
        switch self {
        case .read(let c): return c.frame
        case .placeholder(let c): return c.frame
        }
    }

    /// One-stop factory. Switches once on `ToolGroupChild` (the input
    /// IR) and dispatches to the matching layout's own `make`. The
    /// switch is exhaustive over both enums, so a missing pair shows
    /// up at compile time on either side.
    nonisolated static func make(
        _ child: ToolGroupChild, x: CGFloat, y: CGFloat, width: CGFloat
    ) -> ToolGroupChildLayout {
        switch child {
        case .read(let title):
            return .read(ReadChildLayout.make(
                title: title, x: x, y: y, width: width))
        case .placeholder(let label):
            return .placeholder(PlaceholderChildLayout.make(
                label: label, x: x, y: y, width: width))
        }
    }

    func draw(in ctx: CGContext, origin: CGPoint) {
        switch self {
        case .read(let c): c.draw(in: ctx, origin: origin)
        case .placeholder(let c): c.draw(in: ctx, origin: origin)
        }
    }
}

